'lib/src/snippets/dart_api/expressions.dart.snippet.json': {'(full)': '<span><span class="comment">// ignore_for_file: avoid_single_cascade_in_expression_statements, unused_local_variable</span>\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.drift.dart\'</span>;\n\n<span class="keyword">abstract</span> <span class="keyword">class</span> <span class="class declaration">Animals</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">amountOfLegs</span>;\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">averageLivespan</span>;\n\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/BoolColumn.html">BoolColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">isMammal</span>;\n}\n\n<span class="keyword">class</span> <span class="class declaration">Animal</span> {}\n\n<span class="keyword">abstract</span> <span class="keyword">class</span> <span class="class declaration">Products</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="key