 in real-time</span>\n    <span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/watch.html">watch</a></span>();\n\n    <span class="comment">// To get a single item, apply a filter and call `getSingle`</span>\n    <span class="keyword control">await</span> <span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">id</span>(<span class="number">1</span>)).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/getSingle.html">getSingle</a></span>();\n  }\n\n  <span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">filterTodoItems</span>() <span class="keyword control">async</span> {\n    <span class="comment">// All items with a title of "Title"</span>\n    <span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">title</span>(<span class="string">"Title"</span>));\n\n    <span class="comment">// All items with a title of "Title" and content of "Content"</span>\n    <span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</