ter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">title</span>(<span class="string">"Title"</span>) | <span class="parameter">f</span>.<span class="property instance">content</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnFilters/not.html">not</a></span>.<span class="method instance">isNull</span>());\n}</span>\n','manager_type_specific_filter': '<span><span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">filterWithType</span>() <span class="keyword control">async</span> {\n  <span class="comment">// Filter all items created since 7 days ago</span>\n  <span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>(\n    (<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">createdAt</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateFilters/isAfter.html">isAfter</a></span>(<span class="class constructor">DateTime</span>.<span class="method constructor">now</span>().<span class="method instance">subtract</span>(<span class="class constructor">Duration</span>(<span class="parameter label">days</span>: <span class="number">7</span>))),\n  );\n\n  <span class="comment">// Filter all items with a title that starts with "Title"</span>\n  <span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">title</span