rameter">prefetch</span>(<span class="parameter label">todoItemsRefs</span>: <span class="boolean">true</span>, <span class="parameter label">user</span>: <span class="boolean">true</span>))\n    .<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/watch.html">watch</a></span>()\n    .<span class="method instance">listen</span>((<span class="parameter declaration">catWithRefs</span>) {\n      <span class="keyword control">for</span> (<span class="keyword">final</span> (<span class="variable declaration">cat</span>, <span class="variable declaration">refs</span>) in <span class="parameter">catWithRefs</span>) {\n        <span class="comment">// Updates to the user table will trigger a query</span>\n        <span class="keyword">final</span> <span class="variable declaration">users</span> = <span class="variable">refs</span>.<span class="property instance">user</span>?.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/ProcessedTableManager/prefetchedData.html">prefetchedData</a></span>;\n\n        <span class="comment">// However, updates to the TodoItems table will not trigger a query</span>\n        <span class="keyword">final</span> <span class="variable declaration">todos</span> = <span class="variable">refs</span>.<span class="property instance">todoItemsRefs</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/ProcessedTableManager/prefetchedData.html">prefetchedData</a></span>;\n      }\n    });</span>\n','manager_filter_extensions': '<span><span class="comment">// Extend drifts built-in filters by combining the existing filters to create a new one</span>\n<span class="comment">// or by creating a new filter from scratch</span>\n<span class="keyword">extension</span> <span class="class">After2000Filter</span> <span class="keyword">on</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnFilters-class.html">ColumnFilters</a></span>&lt;<span class="class">DateTime</span>&gt; {\n  <span class="comment">// Create a new filter by combining existing filters</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Expression-class.html">Expression</a></span>&lt;<span class="class">bool</span>&gt; <span class="method declaration instance">after2000orBefore1900</span>() =&gt;\n      <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateFilters/isAfter.html">isAfter</a></span>(<span class="class constructor">DateTime</span>(<span class="number">2000</span>)) | <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateFilters/isBefore.html">isBefore</a></span>(<span class="class constructor">DateTime</span>(<span class="number">1900</span>));\n\n  <span class="comment">// Create a new filter from scratch using the `column` property</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Expression-class.html">Expression</a></span>&lt;<span class="class">bool</span>&gt; <span class="method declaration instance">filterOnUnixEpoch</span>(<span class="class">int</span> <span class="parameter declaration">value</span>) =&gt;\n      <span class="method instance">\$composableFilter</span>(<span class="property instance">column</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeExpressions/unixepoch.html">unixepoch</a></span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Expression/equals.html">equals</a></span>(<span class="parameter">value</span>));\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">filterWithExtension</span>(<span class="class">AppDatabase</span> <span class="parameter declaration">db</span>) <span class="keyword control">async</span> {\n  <span class="comment">// Use the custom filters on any column that is of type DateTime</span>\n  <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">createdAt</span>.<span class="method instance">after2000orBefore1900</span>());\n\n  <span class="comment">// Use the custom filter on the `unixepoch` column</span>\n  <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">createdAt</span>.<span class="method instance">filterOnUnixEpoch</span>(<span class="number">0</span>));\n}</span>\n','manager_ordering_extensions': '<span><span class="comment">// Extend drifts built-in orderings by create a new ordering from scratch</span>\n<span class="keyword">extension</span> <span class="class">After2000Ordering</span> <span class="keyword">on</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings-class.html">ColumnOrderings</a></span>&lt;<span class="class">DateTime</span>&gt; {\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/ComposableOrdering-class.html">ComposableOrdering</a></span> <span class="method declaration instance">byUnixEpoch</span>() =&gt; <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings-class.html">ColumnOrderings</a></span>(<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings/column.html">column</a></span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeExpressions/unixepoch.html">unixepoch</a></span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings/asc.html">asc</a></span>();\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">orderingWithExtension</span>(<span class="class">AppDatabase</span> <span class="parameter declaration">db</span>) <span class="keyword control">async</span> {\n  <span class="comment">// Use the custom orderings on any column that is of type DateTime</span>\n  <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/orderBy.html">orderBy</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="property instance">createdAt</span>.<span class="method instance">byUnixEpoch</span>());\n}</span>\n','manager_custom_filter': '<span><span class="comment">// Extend the generated table filter composer to add a custom filter</span>\n<span class="keyword">extension</span> <span class="class">NoContentOrBefore2000FilterX</span> <span class="keyword">on</span> <span class="class">\$\$TodoItemsTableFilterComposer</span> {\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Expression-class.html">Expression</a></span>&lt;<span class="class">bool</span>&gt; <span class="method declaration instance">noContentOrBefore2000</span>() =&gt;\n      (<span class="property instance">content</span>.<span class="method instance">isNull</span>() | <span class="property instance">createdAt</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateFilters/isBefore.html">isBefore</a></span>(<span class="class constructor">DateTime</span>(<span class="number">2000</span>)));\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">customFilter</span>(<span class="class">AppDatabase</span> <span class="parameter declaration">db</span>) <span class="keyword control">async</span> {\n  <span class="comment">// Use the custom filter on the `TodoItems` table</span>\n  <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="method instance">noContentOrBefore2000</span>());\n}</span>\n','manager_custom_ordering': '<span><span class="comment">// Extend the generated table filter composer to add a custom filter</span>\n<span class="keyword">extension</span> <span class="class">ContentThenCreationDataX</span> <span class="keyword">on</span> <span class="class">\$\$TodoItemsTableOrderingComposer</span> {\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/ComposableOrdering-class.html">ComposableOrdering</a></span> <span class="method declaration instance">contentThenCreatedAt</span>() =&gt; <span class="property instance">content</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings/asc.html">asc</a></span>() &amp; <span class="property instance">createdAt</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings/asc.html">asc</a></span>();\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">customOrdering</span>(<span class="class">AppDatabase</span> <span class="parameter declaration">db</span>) <span class="keyword control">async</span> {\n  <span class="comment">// Use the custom ordering on the `TodoItems` table</span>\n  <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/orderBy.html">orderBy</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="parameter">f</span>.<span class="method instance">contentThenCreatedAt</span>());\n}</span>\n','manager_annotations': '<span><span class="comment">// First create an computed field with an expression you want to use</span>\n<span class="keyword">final</span> <span class="variable declaration">titleLengthField</span> = <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/RootTableManager/computedField.html">computedField</a></span>(\n  (<span class="parameter declaration">o</span>) =&gt; <span class="parameter">o</span>.<span class="property instance">title</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/StringExpressionOperators/length.html">length</a></span>,\n);\n\n<span class="comment documentation">/// Create a copy of the manager with the computed fields you want to use</span>\n<span class="keyword">final</span> <span class="variable declaration">manager</span> = <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/withFields.html">withFields</a></span>([<span class="variable">titleLengthField</span>]);\n\n<span class="comment">// Then use the computed field in a filter</span>\n<span class="comment">// This will filter all items whose title has exactly 10 characters</span>\n<span class="variable">manager</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/filter.html">filter</a></span>((<span class="parameter declaration">f</span>) =&gt; <span class="variable">titleLengthField</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/ComputedField/filter.html">filter</a></span>(<span class="number">10</span>));\n\n<span class="comment">// You can also use the computed field in an ordering</span>\n<span class="comment">// This will order all items by the length of their title in ascending order</span>\n<span class="variable">manager</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/orderBy.html">orderBy</a></span>((<span class="parameter declaration">o</span>) =&gt; <span class="variable">titleLengthField</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseComputedField/order.html">order</a></span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ColumnOrderings/asc.html">asc</a></span>());\n\n<span class="comment documentation">/// You can read the result of the computed field too</span>\n<span class="keyword control">for</span> (<span class="keyword">final</span> (<span class="variable declaration">item</span>, <span class="variable declaration">refs</span>) in <span class="keyword control">await</span> <span class="variable">manager</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/get.html">get</a></span>()) {\n  <span class="keyword">final</span> <span class="variable declaration">titleLength</span> = <span class="variable">titleLengthField</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ComputedField/read.html">read</a></span>(<span class="variable">refs</span>);\n  <span class="function">print</span>(<span class="string">\'Item </span><span class="source interpolation">\${</span><span class="variable">item</span><span class="source interpolation">.</span><span class="property instance">id</span><span class="source interpolation">}</span><span class="string"> has a title length of </span><span class="source interpolation">\$</span><span class="variable">titleLength</span><span class="string">\'</span>);\n}</span>\n','referenced_annotations': '<span><span class="comment">// This computed field will get the name of the user of this todo</span>\n<span class="keyword">final</span> <span class="variable declaration">todoUserName</span> = <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/RootTableManager/computedField.html">computedField</a></span>(\n  (<span class="parameter declaration">o</span>) =&gt; <span class="parameter">o</span>.<span class="property instance">category</span>.<span class="property instance">user</span>.<span class="property instance">name</span>,\n);\n\n<span class="comment documentation">/// Create a copy of the manager with the computed fields you want to use</span>\n<span class="keyword">final</span> <span class="variable declaration">manager</span> = <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoItems</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/withFields.html">withFields</a></span>([<span class="variable">todoUserName</span>]);\n\n<span class="comment documentation">/// You can read the result of the computed field too</span>\n<span class="keyword control">for</span> (<span class="keyword">final</span> (<span class="variable declaration">item</span>, <span class="variable declaration">refs</span>) in <span class="keyword control">await</span> <span class="variable">manager</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/get.html">get</a></span>()) {\n  <span class="keyword">final</span> <span class="variable declaration">userName</span> = <span class="variable">todoUserName</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ComputedField/read.html">read</a></span>(<span class="variable">refs</span>);\n  <span class="function">print</span>(<span class="string">\'Item </span><span class="source interpolation">\${</span><span class="variable">item</span><span class="source interpolation">.</span><span class="property instance">id</span><span class="source interpolation">}</span><span class="string"> has a user with the name </span><span class="source interpolation">\$</span><span class="variable">userName</span><span class="string">\'</span>);\n}</span>\n','aggregated_annotations': '<span><span class="comment">// You can aggregate over multiple rows in a related table</span>\n<span class="comment">// to perform calculations on them</span>\n<span class="keyword">final</span> <span class="variable declaration">todoCountcomputedField</span> = <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoCategory</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/RootTableManager/computedField.html">computedField</a></span>(\n  (<span class="parameter declaration">o</span>) =&gt; <span class="parameter">o</span>.<span class="method instance">todoItemsRefs</span>((<span class="parameter declaration">o</span>) =&gt; <span class="parameter">o</span>.<span class="property instance">id</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseAggregate/count.html">count</a></span>(),\n);\n\n<span class="comment documentation">/// Create a copy of the manager with the computed fields you want to use</span>\n<span class="keyword">final</span> <span class="variable declaration">manager</span> = <span class="parameter">db</span>.<span class="property instance">managers</span>.<span class="property instance">todoCategory</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/withFields.html">withFields</a></span>([<span class="variable">todoCountcomputedField</span>]);\n\n<span class="comment documentation">/// Read the result of the computed field</span>\n<span class="keyword control">for</span> (<span class="keyword">final</span> (<span class="variable declaration">category</span>, <span class="variable declaration">refs</span>) in <span class="keyword control">await</span> <span class="variable">manager</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/get.html">get</a></span>()) {\n  <span class="keyword">final</span> <span class="variable declaration">todoCount</span> = <span class="variable">todoCountcomputedField</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ComputedField/read.html">read</a></span>(<span class="variable">refs</span>);\n  <span class="function">print</span>(<span class="string">\'Category </span><span class="source interpolation">\${</span><span class="variable">category</span><span class="source interpolation">.</span><span class="property instance">id</span><span class="source interpolation">}</span><span class="string"> has </span><span class="source interpolation">\$</span><span class="variable">todoCount</span><span class="string"> todos\'</span>);\n}</span>\n',},
