'lib/src/snippets/dart_api/select.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.drift.dart\'</span>;\n\n<span class="comment">// We define a data class to contain both a todo entry and the associated</span>\n<span class="comment">// category.</span>\n<span class="keyword">class</span> <span class="class declaration">EntryWithCategory</span> {\n  <span class="class constructor declaration">EntryWithCategory</span>(<span class="keyword">this</span>.<span class="variable instance">entry</span>, <span class="keyword">this</span>.<span class="variable instance">category</span>);\n\n  <span class="comment">// The classes are generated by drift for each of the tables involved in the</span>\n  <span class="comment">// join.</span>\n  <span class="keyword">final</span> <span class="class">TodoItem</span> <span class="variable declaration instance">entry</span>;\n  <span class="keyword">final</span> <span class="class">Category</span>? <span class="variable declaration instance">category</span>;\n}\n\n\n<span class="keyword">extension</span> <span class="class">SelectExamples</span> <span class="keyword">on</span> <span class="class">CanUseCommonTables</span> {\n  <span class="class">Future</span>&lt;<span class="class">List</span>&lt;<span class="class">TodoItem</span>&gt;&gt; <span class="method declaration instance">limitTodos</span>(<span class="class">int</span> <span class="parameter declaration">limit</span>, {<span class="class">int</span>? <span class="parameter declaration">offset</span>}) {\n    <span class="keyword control">return</span> (<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/