 <span class="property instance">onDay</span>},\n  ];\n}</span>\n','autoIncrement': '<span><span class="keyword">class</span> <span class="class declaration">Items</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="keyword">late</span> <span class="keyword">final</span> <span class="variable declaration instance">id</span> = <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="keyword">late</span> <span class="keyword">final</span> <span class="variable declaration instance">title</span> = <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>()();\n}</span>\n','autoIncrementUse': '<span><span class="keyword control">await</span> <span class="parameter">database</span>.<span class="property instance">items</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/TableStatements/insertAll.html">insertAll</a></span>([\n  <span class="comment">// Only the title is required here</span>\n  <span class="class constructor">ItemsCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">title</span>: <span class="string">\'First entry\'</span>),\n  <span class="class constructor">ItemsCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">title</span>: <span class="string">\'Another item\'</span>),\n]);\n\n<span class="keyword">final</span> <span class="variable declaration">items</span> = <span class="keyword control">await</span> <span class="parameter">database</span>.<span class="property instance">items</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/TableOrViewStatements/all.html">all</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/get.html">get</a></span>();\n<span class="comment">// This prints [(id: 1, title: First entry), (id: 2, title: Another item)].</span>\n<span class="comment">// The id has been chosen by the database.</span>\n<span class="function">print</span>(<span class="variable">items</span>);</span>\n','autoIncrementUseManager': '<span><span class="keyword control">await</span> <span class="parameter">database</span>.<span class="property instance">managers</span>.<span class="property instance">items</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/RootTableManager/bulkCreate.html">bulkCreate</a></span>(\n  (<span class="parameter declaration">c</span>) =&gt; [<span class="parameter">c</span>(<span class="parameter label">title</span>: <span class="string">\'First entry\'</span>), <span class="parameter">c</span>(<span class="parameter label">title</span>: <span class="string">\'Another item\'</span>)],\n);\n\n<span class="keyword">final</span> <span class="variable declaration">items</span> = <span class="keyword control">await</span> <span class="parameter">database</span>.<span class="property instance">managers</span>.<span class="property instance">items</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseTableManager/get.html">get</a></span>();\n<span class="comment">// This prints [(id: 1, title: First entry), (id: 2, title: Another item)].</span>\n<span class="comment">// The id has been chosen by the database.</span>\n<span class="function">print</span>(<span class="variable">items</span>);</span>\n','index': '<span><span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/TableIndex-class.html">TableInd