tml">columns</a></span>: {<span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/IndexedColumn-class.html">IndexedColumn</a></span>(#loggedAt, <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/IndexedColumn/IndexedColumn.html">orderBy</a></span>: <span class="enum"><a href="https://pub.dev/documentation/drift/latest/drift/OrderingMode.html">OrderingMode</a></span>.<span class="enumMember"><a href="https://pub.dev/documentation/drift/latest/drift">desc</a></span>)},\n<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">LogEntries</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">id</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeColumn.html">DateTimeColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">loggedAt</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/dateTime.html">dateTime</a></span>()();\n}</span>\n','indexsql': '<span><span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/TableIndex-class.html">TableIndex</a></span><span class="annotation">.</span><span class="method constructor annotation"><a href="https://pub.dev/documentation/drift/latest/drift/TableIndex/TableIndex.sql.html">sql</a></span><span class="annotation">(</span><span class="string">\'\'\'\n  CREATE INDEX pending_orders ON orders (creation_time)\n    WHERE status == \'pending\';\n\'\'\'</span><span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">Orders</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">id</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">totalAmount</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeColumn.html">DateTimeColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">creationTime</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/dateTime.html">dateTime</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">status</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>()();\n}</span>\n','strict': '<span><span class="keyword">class</span> <span class="class declaration">Preferences</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">key</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/AnyColumn.html">AnyColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">value</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/sqliteAny.html">sqliteAny</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildGeneralColumn/nullable.html">nullable</a></span>()();\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">Set</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Column-class.html">Column</a></span>&lt;<span class="class">Object</span>&gt;&gt;? <span class="keyword">get</span> <span class="property declaration instance">primaryKey</span> =&gt; {<span class="property instance">key</span>};\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">bool</span> <span class="keyword">get</span> <span class="property declaration instance">isStrict</span> =&gt; <span class="boolean">true</span>;\n}\n</span>\n',},
'lib/src/snippets/dart_api/transactions.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.drift.dart\'</span>;\n\n<span class="keyword">extension</span> <span class="class">Snippets</span> <span class="keyword">on</span> <span class="class">CanUseCommonTables</span> {\n  <span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">deleteCategory</span>(<span class="class">Category</span> <span class="parameter declaration">category</span>) {\n    <span class="keyword control">return</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n      <span class="comment">// first, move the affected todo entries back to the default category</span>\n      <span class="keyword control">await</span> (<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/update.html">update</a></span>(<span class="property instance">todoItems</span>)\n            ..<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/where.html">where</a></span>((<span class="parameter declaration">row</span>) =&gt; <span class="parameter">row</span>.<span class="property instance">category</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Expression/equals.html">equals</a></span>(<span class="parameter">category</span>.<span class="property instance">id</span>)))\n          .<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/UpdateStatement/write.html">write</a></span>(<span class="keyword">const</span> <span class="class constructor">TodoItemsCompanion</span>(<span class="parameter label">category</span>: <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/Value-class.html">Value</a></span>(<span class="keyword">null</span>)));\n\n      <span class="comment">// then, delete the category</span>\n      <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/delete.html">delete</a></span>(<span class="property instance">categories</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DeleteStatement/delete.html">delete</a></span>(<span class="parameter">category</span>);\n    });\n  }\n\n  <span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">nestedTransactions</span>() <span class="keyword control">async</span> {\n    <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n      <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(<span class="property instance">categories</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="class constructor">CategoriesCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">name</span>: <span class="string">\'first\'</span>));\n\n      <span class="comment">// this is a nested transaction:</span>\n      <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n        <span class="comment">// At this point, the first category is visible</span>\n        <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(\n          <span class="property instance">categories</span>,\n        ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="class constructor">CategoriesCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">name</span>: <span class="string">\'second\'</span>));\n        <span class="comment">// Here, the second category is only visible inside this nested</span>\n        <span class="comment">// transaction.</span>\n      });\n\n      <span class="comment">// At this point, the second category is visible here as well.</span>\n\n      <span class="keyword control">try</span> {\n        <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n          <span class="comment">// At this point, both categories are visible</span>\n          <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(\n            <span class="property instance">categories</span>,\n          ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="class constructor">CategoriesCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">name</span>: <span class="string">\'third\'</span>));\n          <span class="comment">// The third category is only visible here.</span>\n          <span class="keyword control">throw</span> <span class="class constructor">Exception</span>(<span class="string">\'Abort in the second nested transaction\'</span>);\n        });\n      } <span class="keyword control">on</span> <span class="class">Exception</span> {\n        <span class="comment">// We\'re catching the exception so that this transaction isn\'t reverted</span>\n        <span class="comment">// as well.</span>\n      }\n\n      <span class="comment">// At this point, the third category is NOT visible, but the other two</span>\n      <span class="comment">// are. The transaction is in the same state as before the second nested</span>\n      <span class="comment">// `transaction()` call.</span>\n    });\n\n    <span class="comment">// After the transaction, two categories are visible.</span>\n  }\n\n}</span>\n','deleteCategory': '<span><span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">deleteCategory</span>(<span class="class">Category</span> <span class="parameter declaration">category</span>) {\n  <span class="keyword control">return</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n    <span class="comment">// first, move the affected todo entries back to the default category</span>\n    <span class="keyword control">await</span> (<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/update.html">update</a></span>(<span class="property instance">todoItems</span>)\n          ..<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/where.html">where</a></span>((<span class="parameter declaration">row</span>) =&gt; <span class="parameter">row</span>.<span class="property instance">category</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Expression/equals.html">equals</a></span>(<span class="parameter">category</span>.<span class="property instance">id</span>)))\n        .<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/UpdateStatement/write.html">write</a></span>(<span class="keyword">const</span> <span class="class constructor">TodoItemsCompanion</span>(<span class="parameter label">category</span>: <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/Value-class.html">Value</a></span>(<span class="keyword">null</span>)));\n\n    <span class="comment">// then, delete the category</span>\n    <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/delete.html">delete</a></span>(<span class="property instance">categories</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DeleteStatement/delete.html">delete</a></span>(<span class="parameter">category</span>);\n  });\n}</span>\n','nested': '<span><span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">nestedTransactions</span>() <span class="keyword control">async</span> {\n  <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n    <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(<span class="property instance">categories</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="class constructor">CategoriesCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">name</span>: <span class="string">\'first\'</span>));\n\n    <span class="comment">// this is a nested transaction:</span>\n    <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n      <span class="comment">// At this point, the first category is visible</span>\n      <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(\n        <span class="property instance">categories</span>,\n      ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="class constructor">CategoriesCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">name</span>: <span class="string">\'second\'</span>));\n      <span class="comment">// Here, the second category is only visible inside this nested</span>\n      <span class="comment">// transaction.</span>\n    });\n\n    <span class="comment">// At this point, the second category is visible here as well.</span>\n\n    <span class="keyword control">try</span> {\n      <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/transaction.html">transaction</a></span>(() <span class="keyword control">async</span> {\n        <span class="comment">// At this point, both categories are visible</span>\n        <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(\n          <span class="property instance">categories</span>,\n        ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="class constructor">CategoriesCompanion</span>.<span class="method constructor">insert</span>(<span class="parameter label">name</span>: <span class="string">\'third\'</span>));\n        <span class="comment">// The third category is only visible here.</span>\n        <span class="keyword control">throw</span> <span class="class constructor">Exception</span>(<span class="string">\'Abort in the second nested transaction\'</span>);\n      });\n    } <span class="keyword control">on</span> <span class="class">Exception</span> {\n      <span class="comment">// We\'re catching the exception so that this transaction isn\'t reverted</span>\n      <span class="comment">// as well.</span>\n    }\n\n    <span class="comment">// At this point, the third category is NOT visible, but the other two</span>\n    <span class="comment">// are. The transaction is in the same state as before the second nested</span>\n    <span class="comment">// `transaction()` call.</span>\n  });\n\n  <span class="comment">// After the transaction, two categories are visible.</span>\n}\n</span>\n',},
'lib/src/snippets/dart_api/views.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">class</span> <span class="class declaration">Todos</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">id</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">title</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildTextColumn/withLength.html">withLength</a></span>(<span class="parameter label">min</span>: <span class="number">6</span>, <span class="parameter label">max</span>: <span class="number">32</span>)();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">content</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildGeneralColumn/named.html">named</a></span>(<span class="string">\'body\'</span>)();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">category</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildGeneralColumn/nullable.html">nullable</a></span>()();\n}\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DataClassName-class.html">DataClassName</a></span><span class="annotation">(</span><span class="string">\'Category\'</span><span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">Categories</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">id</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">description</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>()();\n}\n\n<span class="keyword">abstract</span> <span class="keyword">class</span> <span class="class declaration">CategoryTodoCount</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/View-class.html">View</a></span> {\n  <span class="comment">// Getters define the tables that this view is reading from.</span>\n  <span class="class">Todos</span> <span class="keyword">get</span> <span class="property declaration instance">todos</span>;\n  <span class="class">Categories</span> <span class="keyword">get</span> <span class="property declaration instance">categories</span>;\n\n  <span class="comment">// Custom expressions can be given a name by defining them as a getter:.</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Expression-class.html">Expression</a></span>&lt;<span class="class">int</span>&gt; <span class="keyword">get</span> <span class="property declaration instance">itemCount</span> =&gt; <span class="property instance">todos</span>.<span class="property instance">id</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseAggregate/count.html">count</a></span>();\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Query-class.html">Query</a></span> <span class="method declaration instance">as</span>() =&gt;\n      <span class="comment">// Views can select columns defined as expression getters on the class, or</span>\n      <span class="comment">// they can reference columns from other tables.</span>\n      <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/View/select.html">select</a></span>([<span class="property instance">categories</span>.<span class="property instance">description</span>, <span class="property instance">itemCount</span>]).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/View/from.html">from</a></span>(<span class="property instance">categories</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/JoinedSelectStatement/join.html">join</a></span>([\n        <span class="function"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">innerJoin</a></span>(<span class="property instance">todos</span>, <span class="property instance">todos</span>.<span class="property instance">category</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Expression/equalsExp.html">equalsExp</a></span>(<span class="property instance">categories</span>.<span class="property instance">id</span>)),\n      ]);\n}\n</span>\n','view': '<span><span class="keyword">abstract</span> <span class="keyword">class</span> <span class="class declaration">CategoryTodoCount</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/View-class.html">View</a></span> {\n  <span class="comment">// Getters define the tables that this view is reading from.</span>\n  <span class="class">Todos</span> <span class="keyword">get</span> <span class="property declaration instance">todos</span>;\n  <span class="class">Categories</span> <span class="keyword">get</span> <span class="property declaration instance">categories</span>;\n\n  <span class="comment">// Custom expressions can be given a name by defining them as a getter:.</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Expression-class.html">Expression</a></span>&lt;<span class="class">int</span>&gt; <span class="keyword">get</span> <span class="property declaration instance">itemCount</span> =&gt; <span class="property instance">todos</span>.<span class="property instance">id</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BaseAggregate/count.html">count</a></span>();\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Query-class.html">Query</a></span> <span class="method declaration instance">as</span>() =&gt;\n      <span class="comment">// Views can select columns defined as expression getters on the class, or</span>\n      <span class="comment">// they can reference columns from other tables.</span>\n      <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/View/select.html">select</a></span>([<span class="property instance">categories</span>.<span class="property instance">description</span>, <span class="property instance">itemCount</span>]).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/View/from.html">from</a></span>(<span class="property instance">categories</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/JoinedSelectStatement/join.html">join</a></span>([\n        <span class="function"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">innerJoin</a></span>(<span class="property instance">todos</span>, <span class="property instance">todos</span>.<span class="property instance">category</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Expression/equalsExp.html">equalsExp</a></span>(<span class="property instance">categories</span>.<span class="property instance">id</span>)),\n      ]);\n}\n</span>\n',},
'lib/src/snippets/drift_files/custom_queries.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'../_shared/todo_tables.drift.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'custom_queries.drift.dart\'</span>;\n\n<span class="keyword">class</span> <span class="class declaration">CategoryWithCount</span> {\n  <span class="keyword">final</span> <span class="class">Category</span> <span class="variable declaration instance">category</span>;\n  <span class="keyword">final</span> <span class="class">int</span> <span class="variable declaration instance">count</span>; <span class="comment">// amount of entries in this category</span>\n\n  <span class="class constructor declaration">CategoryWithCount</span>({<span class="keyword">required</span> <span class="keyword">this</span>.<span class="variable instance">category</span>, <span class="keyword">required</span> <span class="keyword">this</span>.<span class="variable instance">count</span>});\n}\n\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span>\n  <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">tables</a></span>: [<span class="class">TodoItems</span>, <span class="class">Categories</span>],\n  <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">queries</a></span>: {\n    <span class="string">\'categoriesWithCount\'</span>:\n        <span class="string">\'SELECT *, \'</span>\n        <span class="string">\'(SELECT COUNT(*) FROM todo_items WHERE category = c.id) AS "amount" \'</span>\n        <span class="string">\'FROM categories c;\'</span>,\n  },\n<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">MyDatabase</span> <span class="keyword">extends</span> <span class="class">\$MyDatabase</span> {\n  <span class="comment">// rest of class stays the same</span>\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n\n  <span class="class constructor declaration">MyDatabase</span>(<span class="keyword">super</span>.<span class="parameter declaration">e</span>);\n\n  <span class="class">Stream</span>&lt;<span class="class">int</span>&gt; <span class="method declaration instance">amountOfTodosInCategory</span>(<span class="class">int</span> <span class="parameter declaration">id</span>) {\n    <span class="keyword control">return</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">customSelect</a></span>(\n      <span class="string">\'SELECT COUNT(*) AS c FROM todo_items WHERE category = ?\'</span>,\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">variables</a></span>: [<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Variable-class.html">Variable</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/drift/Variable/withInt.html">withInt</a></span>(<span class="parameter">id</span>)],\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">readsFrom</a></span>: {<span class="property instance">todoItems</span>},\n    ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/map.html">map</a></span>((<span class="parameter declaration">row</span>) =&gt; <span class="parameter">row</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/QueryRow/read.html">read</a></span>&lt;<span class="class">int</span>&gt;(<span class="string">\'c\'</span>)).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/watchSingle.html">watchSingle</a></span>();\n  }\n\n  <span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">useGeneratedQuery</span>() <span class="keyword control">async</span> {\n    <span class="comment">// The generated query can be run once as a future:</span>\n    <span class="keyword control">await</span> <span class="method instance">categoriesWithCount</span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/get.html">get</a></span>();\n\n    <span class="comment">// Or multiple times as a stream</span>\n    <span class="keyword control">await</span> <span class="keyword control">for</span> (<span class="keyword">final</span> <span class="variable declaration">snapshot</span> <span class="keyword control">in</span> <span class="method instance">categoriesWithCount</span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/watch.html">watch</a></span>()) {\n      <span class="function">print</span>(<span class="string">\'Found </span><span class="source interpolation">\${</span><span class="variable">snapshot</span><span class="source interpolation">.</span><span class="property instance">length</span><span class="source interpolation">}</span><span class="string"> category results\'</span>);\n    }\n  }\n\n  <span class="comment">// then, in the database class:</span>\n  <span class="class">Stream</span>&lt;<span class="class">List</span>&lt;<span class="class">CategoryWithCount</span>&gt;&gt; <span class="method declaration instance">allCategoriesWithCount</span>() {\n    <span class="comment">// select all categories and load how many associated entries there are for</span>\n    <span class="comment">// each category</span>\n    <span class="keyword control">return</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">customSelect</a></span>(\n      <span class="string">\'SELECT *, (SELECT COUNT(*) FROM todos WHERE category = c.id) AS "amount"\'</span>\n      <span class="string">\' FROM categories c;\'</span>,\n      <span class="comment">// used for the stream: the stream will update when either table changes</span>\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">readsFrom</a></span>: {<span class="property instance">todoItems</span>, <span class="property instance">categories</span>},\n    ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/watch.html">watch</a></span>().<span class="method instance">map</span>((<span class="parameter declaration">rows</span>) {\n      <span class="comment">// we get list of rows here. We just have to turn the raw data from the</span>\n      <span class="comment">// row into a CategoryWithCount instnace. As we defined the Category table</span>\n      <span class="comment">// earlier, drift knows how to parse a category. The only thing left to do</span>\n      <span class="comment">// manually is extracting the amount.</span>\n      <span class="keyword control">return</span> <span class="parameter">rows</span>\n          .<span class="method instance">map</span>(\n            (<span class="parameter declaration">row</span>) =&gt; <span class="class constructor">CategoryWithCount</span>(\n              <span class="parameter label">category</span>: <span class="property instance">categories</span>.<span class="method instance">map</span>(<span class="parameter">row</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/QueryRow/data.html">data</a></span>),\n              <span class="parameter label">count</span>: <span class="parameter">row</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/QueryRow/read.html">read</a></span>&lt;<span class="class">int</span>&gt;(<span class="string">\'amount\'</span>),\n            ),\n          )\n          .<span class="method instance">toList</span>();\n    });\n  }\n\n\n}\n</span>\n','manual': '<span><span class="keyword">class</span> <span class="class declaration">CategoryWithCount</span> {\n  <span class="keyword">final</span> <span class="class">Category</span> <span class="variable declaration instance">category</span>;\n  <span class="keyword">final</span> <span class="class">int</span> <span class="variable declaration instance">count</span>; <span class="comment">// amount of entries in this category</span>\n\n  <span class="class constructor declaration">CategoryWithCount</span>({<span class="keyword">required</span> <span class="keyword">this</span>.<span class="variable instance">category</span>, <span class="keyword">required</span> <span class="keyword">this</span>.<span class="variable instance">count</span>});\n}\n\n<span class="comment">// then, in the database class:</span>\n<span class="class">Stream</span>&lt;<span class="class">List</span>&lt;<span class="class">CategoryWithCount</span>&gt;&gt; <span class="method declaration instance">allCategoriesWithCount</span>() {\n  <span class="comment">// select all categories and load how many associated entries there are for</span>\n  <span class="comment">// each category</span>\n  <span class="keyword control">return</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">customSelect</a></span>(\n    <span class="string">\'SELECT *, (SELECT COUNT(*) FROM todos WHERE category = c.id) AS "amount"\'</span>\n    <span class="string">\' FROM categories c;\'</span>,\n    <span class="comment">// used for the stream: the stream will update when either table changes</span>\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">readsFrom</a></span>: {<span class="property instance">todoItems</span>, <span class="property instance">categories</span>},\n  ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/watch.html">watch</a></span>().<span class="method instance">map</span>((<span class="parameter declaration">rows</span>) {\n    <span class="comment">// we get list of rows here. We just have to turn the raw data from the</span>\n    <span class="comment">// row into a CategoryWithCount instnace. As we defined the Category table</span>\n    <span class="comment">// earlier, drift knows how to parse a category. The only thing left to do</span>\n    <span class="comment">// manually is extracting the amount.</span>\n    <span class="keyword control">return</span> <span class="parameter">rows</span>\n        .<span class="method instance">map</span>(\n          (<span class="parameter declaration">row</span>) =&gt; <span class="class constructor">CategoryWithCount</span>(\n            <span class="parameter label">category</span>: <span class="property instance">categories</span>.<span class="method instance">map</span>(<span class="parameter">row</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/QueryRow/data.html">data</a></span>),\n            <span class="parameter label">count</span>: <span class="parameter">row</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/QueryRow/read.html">read</a></span>&lt;<span class="class">int</span>&gt;(<span class="string">\'amount\'</span>),\n          ),\n        )\n        .<span class="method instance">toList</span>();\n  });\n}\n</span>\n','setup': '<span><span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span>\n  <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">tables</a></span>: [<span class="class">TodoItems</span>, <span class="class">Categories</span>],\n  <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">queries</a></span>: {\n    <span class="string">\'categoriesWithCount\'</span>:\n        <span class="string">\'SELECT *, \'</span>\n        <span class="string">\'(SELECT COUNT(*) FROM todo_items WHERE category = c.id) AS "amount" \'</span>\n        <span class="string">\'FROM categories c;\'</span>,\n  },\n<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">MyDatabase</span> <span class="keyword">extends</span> <span class="class">\$MyDatabase</span> {\n  <span class="comment">// rest of class stays the same</span>\n}\n</span>\n','amountOfTodosInCategory': '<span><span class="class">Stream</span>&lt;<span class="class">int</span>&gt; <span class="method declaration instance">amountOfTodosInCategory</span>(<span class="class">int</span> <span class="parameter declaration">id</span>) {\n  <span class="keyword control">return</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">customSelect</a></span>(\n    <span class="string">\'SELECT COUNT(*) AS c FROM todo_items WHERE category = ?\'</span>,\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">variables</a></span>: [<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Variable-class.html">Variable</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/drift/Variable/withInt.html">withInt</a></span>(<span class="parameter">id</span>)],\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">readsFrom</a></span>: {<span class="property instance">todoItems</span>},\n  ).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/map.html">map</a></span>((<span class="parameter declaration">row</span>) =&gt; <span class="parameter">row</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/QueryRow/read.html">read</a></span>&lt;<span class="class">int</span>&gt;(<span class="string">\'c\'</span>)).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/watchSingle.html">watchSingle</a></span>();\n}</span>\n','run': '<span><span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">useGeneratedQuery</span>() <span class="keyword control">async</span> {\n  <span class="comment">// The generated query can be run once as a future:</span>\n  <span class="keyword control">await</span> <span class="method instance">categoriesWithCount</span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/get.html">get</a></span>();\n\n  <span class="comment">// Or multiple times as a stream</span>\n  <span class="keyword control">await</span> <span class="keyword control">for</span> (<span class="keyword">final</span> <span class="variable declaration">snapshot</span> <span class="keyword control">in</span> <span class="method instance">categoriesWithCount</span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/watch.html">watch</a></span>()) {\n    <span class="function">print</span>(<span class="string">\'Found </span><span class="source interpolation">\${</span><span class="variable">snapshot</span><span class="source interpolation">.</span><span class="property instance">length</span><span class="source interpolation">}</span><span class="string"> category results\'</span>);\n  }\n}\n</span>\n',},
'lib/src/snippets/drift_files/database.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n\n<span class="keyword">part</span> <span class="string">\'database.g.dart\'</span>;\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">include</a></span>: {<span class="string">\'tables.drift\'</span>}<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">MyDb</span> <span class="keyword">extends</span> <span class="class">_\$MyDb</span> {\n  <span class="comment">// This example creates a simple in-memory database (without actual</span>\n  <span class="comment">// persistence).</span>\n  <span class="comment">// To store data, see the database setups from other "Getting started" guides.</span>\n  <span class="class constructor declaration">MyDb</span>() : <span class="keyword">super</span>(<span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/NativeDatabase.memory.html">memory</a></span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n}\n\n<span class="keyword">extension</span> <span class="class">MoreSnippets</span> <span class="keyword">on</span> <span class="class">MyDb</span> {\n  <span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">insert</span>(<span class="class">TodosCompanion</span> <span class="parameter declaration">companion</span>) <span class="keyword control">async</span> {\n    <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(<span class="property instance">todos</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="parameter">companion</span>);\n  }\n\n}</span>\n','overview': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n\n<span class="keyword">part</span> <span class="string">\'database.g.dart\'</span>;\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">include</a></span>: {<span class="string">\'tables.drift\'</span>}<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">MyDb</span> <span class="keyword">extends</span> <span class="class">_\$MyDb</span> {\n  <span class="comment">// This example creates a simple in-memory database (without actual</span>\n  <span class="comment">// persistence).</span>\n  <span class="comment">// To store data, see the database setups from other "Getting started" guides.</span>\n  <span class="class constructor declaration">MyDb</span>() : <span class="keyword">super</span>(<span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/NativeDatabase.memory.html">memory</a></span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n}</span>\n','dart_interop_insert': '<span><span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="method declaration instance">insert</span>(<span class="class">TodosCompanion</span> <span class="parameter declaration">companion</span>) <span class="keyword control">async</span> {\n  <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(<span class="property instance">todos</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(<span class="parameter">companion</span>);\n}\n</span>\n',},
'lib/src/snippets/drift_files/getting_started/database.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="comment">// These imports are used to open the database</span>\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n\n<span class="keyword">part</span> <span class="string">\'database.g.dart\'</span>;\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span>\n  <span class="comment">// relative import for the drift file. Drift also supports `package:`</span>\n  <span class="comment">// imports</span>\n  <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">include</a></span>: {<span class="string">\'tables.drift\'</span>},\n<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">AppDb</span> <span class="keyword">extends</span> <span class="class">_\$AppDb</span> {\n  <span class="class constructor declaration">AppDb</span>() : <span class="keyword">super</span>(<span class="function">_openConnection</span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n}\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span> <span class="function declaration static">_openConnection</span>() {\n  <span class="comment">// the LazyDatabase util lets us find the right location for the file async.</span>\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span>(() <span class="keyword control">async</span> {\n    <span class="comment">// put the database file, called db.sqlite here, into the documents folder</span>\n    <span class="comment">// for your app.</span>\n    <span class="keyword">final</span> <span class="variable declaration">dbFolder</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n    <span class="keyword">final</span> <span class="variable declaration">file</span> = <span class="class constructor">File</span>(<span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dbFolder</span>.<span class="property instance">path</span>, <span class="string">\'db.sqlite\'</span>));\n\n    <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="variable">file</span>);\n  });\n}</span>\n',},
'lib/src/snippets/drift_files/getting_started/tables.drift.snippet.json': {'(full)': '<span><span class="comment">-- this is the tables.drift file</span>\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">todos</span> (\n    <span class="property">id</span> <span class="type">INT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> <span class="keyword">AUTOINCREMENT</span>,\n    <span class="property">title</span> <span class="type">TEXT</span>,\n    <span class="property">body</span> <span class="type">TEXT</span>,\n    <span class="property">category</span> <span class="type">INT</span> <span class="keyword">REFERENCES</span> <span class="class">categories</span> (<span class="property">id</span>)\n);\n\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">categories</span> (\n    <span class="property">id</span> <span class="type">INT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> <span class="keyword">AUTOINCREMENT</span>,\n    <span class="property">description</span> <span class="type">TEXT</span>\n) <span class="keyword">AS</span> Category; <span class="comment">-- see the explanation on "AS Category" below</span>\n\n<span class="comment">/* after declaring your tables, you can put queries in here. Just\n   write the name of the query, a colon (:) and the SQL: */</span>\n<span class="function declaration">todosInCategory</span>: <span class="keyword">SELECT</span> * <span class="keyword">FROM</span> <span class="class">todos</span> <span class="keyword">WHERE</span> <span class="property">category</span> = <span class="variable">?</span>;\n\n<span class="comment">/* Here\'s a more complex query: It counts the amount of entries per\ncategory, including those entries which aren\'t in any category at all. */</span>\n<span class="function declaration">countEntries</span>:\n  <span class="keyword">SELECT</span>\n    <span class="property">c.description</span>,\n    (<span class="keyword">SELECT</span> COUNT(*) <span class="keyword">FROM</span> <span class="class">todos</span> <span class="keyword">WHERE</span> <span class="property">category</span> = <span class="property">c.id</span>) <span class="keyword">AS</span> amount\n  <span class="keyword">FROM</span> <span class="class">categories</span> c\n  <span class="keyword">UNION</span> <span class="keyword">ALL</span>\n  <span class="keyword">SELECT</span> <span class="keyword">null</span>, (<span class="keyword">SELECT</span> COUNT(*) <span class="keyword">FROM</span> <span class="class">todos</span> <span class="keyword">WHERE</span> <span class="property">category</span> <span class="keyword">IS</span> <span class="keyword">NULL</span>);</span>\n',},
'lib/src/snippets/drift_files/getting_started/tables.expr.temp.dart.snippet.json': {'(full)': '<span></span>\n',},
'lib/src/snippets/drift_files/nested.drift.snippet.json': {'(full)': '<span><span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">coordinates</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">lat</span> <span class="type">REAL</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>,\n  <span class="property">long</span> <span class="type">REAL</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>\n);\n\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">saved_routes</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">name</span> <span class="type">TEXT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>,\n  <span class="property">"from"</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">coordinates</span> (<span class="property">id</span>),\n  <span class="property">"to"</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">coordinates</span> (<span class="property">id</span>)\n);\n\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">route_points</span> (\n  <span class="property">route</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">saved_routes</span> (<span class="property">id</span>),\n  <span class="property">point</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">coordinates</span> (<span class="property">id</span>),\n  <span class="property">index_on_route</span> <span class="type">INTEGER</span>,\n  <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> (<span class="property">route</span>, <span class="property">point</span>)\n);\n\n<span class="function declaration">routesWithPoints</span>: <span class="keyword">SELECT</span> <span class="property">r.id</span>, <span class="property">r.name</span>, f.*, t.* <span class="keyword">FROM</span> <span class="class">saved_routes</span> r\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> f <span class="keyword">ON</span> <span class="property">f.id</span> = <span class="property">r."from"</span>\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> t <span class="keyword">ON</span> <span class="property">t.id</span> = <span class="property">r."to"</span>;\n<span class="function declaration">routesWithNestedPoints</span>: <span class="keyword">SELECT</span> <span class="property">r.id</span>, <span class="property">r.name</span>, f.** <span class="keyword">AS</span> "from", t.** <span class="keyword">AS</span> "to" <span class="keyword">FROM</span> <span class="class">saved_routes</span> r\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> f <span class="keyword">ON</span> <span class="property">f.id</span> = <span class="property">r."from"</span>\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> t <span class="keyword">ON</span> <span class="property">t.id</span> = <span class="property">r."to"</span>;\n<span class="function declaration">routeWithPoints</span>: <span class="keyword">SELECT</span>\n    route.**,\n    <span class="keyword">LIST</span>(<span class="keyword">SELECT</span> coordinates.* <span class="keyword">FROM</span> <span class="class">route_points</span>\n      <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> <span class="keyword">ON</span> <span class="property">id</span> = <span class="property">point</span>\n      <span class="keyword">WHERE</span> <span class="property">route</span> = <span class="property">route.id</span>\n      <span class="keyword">ORDER</span> <span class="keyword">BY</span> <span class="property">index_on_route</span>\n    ) <span class="keyword">AS</span> points\n  <span class="keyword">FROM</span> <span class="class">saved_routes</span> route;</span>\n','overview': '<span><span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">coordinates</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">lat</span> <span class="type">REAL</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>,\n  <span class="property">long</span> <span class="type">REAL</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>\n);\n\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">saved_routes</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">name</span> <span class="type">TEXT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>,\n  <span class="property">"from"</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">coordinates</span> (<span class="property">id</span>),\n  <span class="property">"to"</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">coordinates</span> (<span class="property">id</span>)\n);\n\n<span class="function declaration">routesWithPoints</span>: <span class="keyword">SELECT</span> <span class="property">r.id</span>, <span class="property">r.name</span>, f.*, t.* <span class="keyword">FROM</span> <span class="class">saved_routes</span> r\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> f <span class="keyword">ON</span> <span class="property">f.id</span> = <span class="property">r."from"</span>\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> t <span class="keyword">ON</span> <span class="property">t.id</span> = <span class="property">r."to"</span>;</span>\n','route_points': '<span><span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">route_points</span> (\n  <span class="property">route</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">saved_routes</span> (<span class="property">id</span>),\n  <span class="property">point</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">coordinates</span> (<span class="property">id</span>),\n  <span class="property">index_on_route</span> <span class="type">INTEGER</span>,\n  <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> (<span class="property">route</span>, <span class="property">point</span>)\n);</span>\n','nested': '<span><span class="function declaration">routesWithNestedPoints</span>: <span class="keyword">SELECT</span> <span class="property">r.id</span>, <span class="property">r.name</span>, f.** <span class="keyword">AS</span> "from", t.** <span class="keyword">AS</span> "to" <span class="keyword">FROM</span> <span class="class">saved_routes</span> r\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> f <span class="keyword">ON</span> <span class="property">f.id</span> = <span class="property">r."from"</span>\n  <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> t <span class="keyword">ON</span> <span class="property">t.id</span> = <span class="property">r."to"</span>;</span>\n','list': '<span><span class="function declaration">routeWithPoints</span>: <span class="keyword">SELECT</span>\n    route.**,\n    <span class="keyword">LIST</span>(<span class="keyword">SELECT</span> coordinates.* <span class="keyword">FROM</span> <span class="class">route_points</span>\n      <span class="keyword">INNER</span> <span class="keyword">JOIN</span> <span class="class">coordinates</span> <span class="keyword">ON</span> <span class="property">id</span> = <span class="property">point</span>\n      <span class="keyword">WHERE</span> <span class="property">route</span> = <span class="property">route.id</span>\n      <span class="keyword">ORDER</span> <span class="keyword">BY</span> <span class="property">index_on_route</span>\n    ) <span class="keyword">AS</span> points\n  <span class="keyword">FROM</span> <span class="class">saved_routes</span> route;</span>\n',},
