'lib/src/snippets/examples/existing_databases_flutter.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">\'package:drift_flutter/drift_flutter.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:flutter/services.dart\'</span> <span class="keyword">show</span> <span class="variable declaration">rootBundle</span>;\n<span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">openConnection</span>() {\n  <span class="keyword control">return</span> <span class="function"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">driftDatabase</a></span>(\n    <span class="comment">// By default, drift creates a file named app.sqlite based on the name here.</span>\n    <span class="comment">// Because we need to interact with the underlying file, we add the</span>\n    <span class="comment">// `databasePath` option to specify the exact path here.</span>\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">name</a></span>: <span class="string">\'app\'</span>,\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">native</a></span>: <span class="class constructor"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/DriftNativeOptions-class.html">DriftNativeOptions</a></span>(\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/DriftNativeOptions/DriftNativeOptions.html">databasePath</a></span>: () <span class="keyword control">async</span> {\n        <span class="comment">// put the database file, called db.sqlite here, into the documents</span>\n        <span class="comment">// folder for your app.</span>\n        <span class="keyword">final</span> <span class="variable declaration">dbFolder</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n        <span class="keyword">final</span> <span class="variable declaration">file</span> = <span class="class constructor">File</span>(<span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dbFolder</span>.<span class="property instance">path</span>, <span class="string">\'app.db\'</span>));\n\n        <span class="keyword control">if</span> (!<span class="keyword control">await</span> <span class="variable">file</span>.<span class="method instance">exists</span>()) {\n          <span class="comment">// Extract the pre-populated database file from assets</span>\n          <span class="keyword">final</span> <span class="variable declaration">blob</span> = <span class="keyword control">await</span> <span class="property">rootBundle</span>.<span class="method instance">load</span>(<span class="string">\'assets/my_database.db\'</span>);\n          <span class="keyword">final</span> <span class="variable declaration">buffer</span> = <span class="variable">blob</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedData/buffer.html">buffer</a></span>;\n          <span class="keyword control">await</span> <span class="variable">file</span>.<span class="method instance">writeAsBytes</span>(\n            <span class="variable">buffer</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ByteBuffer/asUint8List.html">asUint8List</a></span>(<span class="variable">blob</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedData/offsetInBytes.html">offsetInBytes</a></span>, <span class="variable">blob</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedData/lengthInBytes.html">lengthInBytes</a></span>),\n          );\n        }\n\n        <span class="keyword control">return</span> <span class="variable">file</span>.<span class="property instance">path</span>;\n      },\n    ),\n  );\n}</span>\n',},
'lib/src/snippets/examples/existing_databases_native.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:flutter/services.dart\'</span> <span class="keyword">show</span> <span class="variable declaration">rootBundle</span>;\n<span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3/sqlite3.dart\'</span>;\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">openConnection</span>() {\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span>(() <span class="keyword control">async</span> {\n    <span class="comment">// put the database file, called db.sqlite here, into the documents folder</span>\n    <span class="comment">// for your app.</span>\n    <span class="keyword">final</span> <span class="variable declaration">dbFolder</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n    <span class="keyword">final</span> <span class="variable declaration">file</span> = <span class="class constructor">File</span>(<span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dbFolder</span>.<span class="property instance">path</span>, <span class="string">\'app.db\'</span>));\n\n    <span class="keyword control">if</span> (!<span class="keyword control">await</span> <span class="variable">file</span>.<span class="method instance">exists</span>()) {\n      <span class="comment">// Extract the pre-populated database file from assets</span>\n      <span class="keyword">final</span> <span class="variable declaration">blob</span> = <span class="keyword control">await</span> <span class="property">rootBundle</span>.<span class="method instance">load</span>(<span class="string">\'assets/my_database.db\'</span>);\n      <span class="keyword">final</span> <span class="variable declaration">buffer</span> = <span class="variable">blob</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedData/buffer.html">buffer</a></span>;\n      <span class="keyword control">await</span> <span class="variable">file</span>.<span class="method instance">writeAsBytes</span>(\n        <span class="variable">buffer</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ByteBuffer/asUint8List.html">asUint8List</a></span>(<span class="variable">blob</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedData/offsetInBytes.html">offsetInBytes</a></span>, <span class="variable">blob</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedData/lengthInBytes.html">lengthInBytes</a></span>),\n      );\n    }\n\n    <span class="comment">// Make sqlite3 pick a more suitable location for temporary files - the</span>\n    <span class="comment">// one from the system may be inaccessible due to sandboxing.</span>\n    <span class="keyword">final</span> <span class="variable declaration">cachebase</span> = (<span class="keyword control">await</span> <span class="function">getTemporaryDirectory</span>()).<span class="property instance">path</span>;\n    <span class="comment">// We can\'t access /tmp on Android, which sqlite3 would try by default.</span>\n    <span class="comment">// Explicitly tell it about the correct temporary directory.</span>\n    <span class="property">sqlite3</span>.<span class="property instance">tempDirectory</span> = <span class="variable">cachebase</span>;\n\n    <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="variable">file</span>);\n  });\n}</span>\n',},
'lib/src/snippets/isolates.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n<span class="keyword">import</span> <span class="string">\'dart:isolate\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/isolate/isolate-library.html">\'package:drift/isolate.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n\n<span class="keyword">part</span> <span class="string">\'isolates.g.dart\'</span>;\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">_openConnection</span>() {\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/NativeDatabase.memory.html">memory</a></span>();\n}\n\n<span class="keyword">class</span> <span class="class declaration">SomeTable</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">id</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">content</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>()();\n}\n\n<span class="comment">// Copying the definitions here because we can\'t import Flutter in documentation</span>\n<span class="comment">// snippets.</span>\n<span class="keyword">class</span> <span class="class declaration">RootIsolateToken</span> {\n  <span class="keyword">static</span> <span class="class">RootIsolateToken</span>? <span class="variable declaration static">instance</span>;\n}\n\n<span class="keyword">class</span> <span class="class declaration">BackgroundIsolateBinaryMessenger</span> {\n  <span class="keyword">static</span> <span class="keyword void">void</span> <span class="method declaration static">ensureInitialized</span>(<span class="class">RootIsolateToken</span> <span class="parameter declaration">token</span>) {}\n}\n\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">tables</a></span>: [<span class="class">SomeTable</span>] <span class="comment">/* ... */</span><span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">MyDatabase</span> <span class="keyword">extends</span> <span class="class">_\$MyDatabase</span> {\n  <span class="comment">// A constructor like this can use the default connection as described in the</span>\n  <span class="comment">// getting started guide, but also allows overriding the connection.</span>\n  <span class="class constructor declaration">MyDatabase</span>([<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span>? <span class="parameter declaration">executor</span>]) : <span class="keyword">super</span>(<span class="parameter">executor</span> ?? <span class="function">_openConnection</span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n}\n\n<span class="class">Future</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>&gt; <span class="function declaration static">createIsolateWithSpawn</span>() <span class="keyword control">async</span> {\n  <span class="keyword">final</span> <span class="variable declaration">token</span> = <span class="class">RootIsolateToken</span>.<span class="property static">instance</span>!;\n  <span class="keyword control">return</span> <span class="keyword control">await</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/spawn.html">spawn</a></span>(() {\n    <span class="comment">// This function runs in a new isolate, so we must first initialize the</span>\n    <span class="comment">// messenger to use platform channels.</span>\n    <span class="class">BackgroundIsolateBinaryMessenger</span>.<span class="method static">ensureInitialized</span>(<span class="variable">token</span>);\n\n    <span class="comment">// The callback to DriftIsolate.spawn() must return the database connection</span>\n    <span class="comment">// to use.</span>\n    <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span>(() <span class="keyword control">async</span> {\n      <span class="comment">// Note that this runs on a background isolate, which only started to</span>\n      <span class="comment">// support platform channels in Flutter 3.7. For earlier Flutter versions,</span>\n      <span class="comment">// a workaround is described later in this article.</span>\n      <span class="keyword">final</span> <span class="variable declaration">dbFolder</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n      <span class="keyword">final</span> <span class="variable declaration">path</span> = <span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dbFolder</span>.<span class="property instance">path</span>, <span class="string">\'app.db\'</span>);\n\n      <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>(<span class="class constructor">File</span>(<span class="variable">path</span>));\n    });\n  });\n}\n\n<span class="class">Future</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>&gt; <span class="function declaration static">createIsolateManually</span>() <span class="keyword control">async</span> {\n  <span class="keyword">final</span> <span class="variable declaration">receiveIsolate</span> = <span class="class constructor">ReceivePort</span>(<span class="string">\'receive drift isolate handle\'</span>);\n  <span class="keyword control">await</span> <span class="class">Isolate</span>.<span class="method static">spawn</span>&lt;<span class="class">SendPort</span>&gt;((<span class="parameter declaration">message</span>) <span class="keyword control">async</span> {\n    <span class="keyword">final</span> <span class="variable declaration">server</span> = <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/DriftIsolate.inCurrent.html">inCurrent</a></span>(() {\n      <span class="comment">// Again, this needs to return the LazyDatabase or the connection to use.</span>\n      <span class="keyword control">throw</span> <span class="string">\'stub\'</span>;\n    });\n\n    <span class="comment">// Now, inform the original isolate about the created server:</span>\n    <span class="parameter">message</span>.<span class="method instance">send</span>(<span class="variable">server</span>);\n  }, <span class="variable">receiveIsolate</span>.<span class="property instance">sendPort</span>);\n\n  <span class="keyword">final</span> <span class="variable declaration">server</span> = <span class="keyword control">await</span> <span class="variable">receiveIsolate</span>.<span class="property instance">first</span> <span class="keyword">as</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>;\n  <span class="variable">receiveIsolate</span>.<span class="method instance">close</span>();\n  <span class="keyword control">return</span> <span class="variable">server</span>;\n}\n\n<span class="class">Future</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>&gt; <span class="function declaration static">createIsolate</span>() =&gt; <span class="function">createIsolateWithSpawn</span>();\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() <span class="keyword control">async</span> {\n  <span class="keyword">final</span> <span class="variable declaration">isolate</span> = <span class="keyword control">await</span> <span class="function">createIsolate</span>();\n\n  <span class="comment">// After creating the isolate, calling connect() will return a connection</span>\n  <span class="comment">// which can be used to create a database.</span>\n  <span class="comment">// As long as the isolate is used by only one database (it is here), we can</span>\n  <span class="comment">// use `singleClientMode` to dispose the isolate after closing the connection.</span>\n  <span class="keyword">final</span> <span class="variable declaration">database</span> = <span class="class constructor">MyDatabase</span>(<span class="keyword control">await</span> <span class="variable">isolate</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">connect</a></span>(<span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">singleClientMode</a></span>: <span class="boolean">true</span>));\n\n  <span class="comment">// you can now use your database exactly like you regularly would, it</span>\n  <span class="comment">// transparently uses a background isolate to execute queries.</span>\n  <span class="comment">// Just using the db to avoid an analyzer error, this isn\'t part of the docs.</span>\n  <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customSelect.html">customSelect</a></span>(<span class="string">\'SELECT 1\'</span>);\n}\n\n<span class="keyword void">void</span> <span class="function declaration static">connectSynchronously</span>() {\n  <span class="class constructor">MyDatabase</span>(\n    <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection/DatabaseConnection.delayed.html">delayed</a></span>(\n      <span class="class constructor">Future</span>.<span class="method constructor">sync</span>(() <span class="keyword control">async</span> {\n        <span class="keyword">final</span> <span class="variable declaration">isolate</span> = <span class="keyword control">await</span> <span class="function">createIsolate</span>();\n        <span class="keyword control">return</span> <span class="variable">isolate</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">connect</a></span>(<span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">singleClientMode</a></span>: <span class="boolean">true</span>);\n      }),\n    ),\n  );\n}\n\n\n<span class="class">Future</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>&gt; <span class="function declaration static">_createDriftIsolate</span>() <span class="keyword control">async</span> {\n  <span class="comment">// this method is called from the main isolate. Since we can\'t use</span>\n  <span class="comment">// getApplicationDocumentsDirectory on a background isolate, we calculate</span>\n  <span class="comment">// the database path in the foreground isolate and then inform the</span>\n  <span class="comment">// background isolate about the path.</span>\n  <span class="keyword">final</span> <span class="variable declaration">dir</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n  <span class="keyword">final</span> <span class="variable declaration">path</span> = <span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dir</span>.<span class="property instance">path</span>, <span class="string">\'db.sqlite\'</span>);\n  <span class="keyword">final</span> <span class="variable declaration">receivePort</span> = <span class="class constructor">ReceivePort</span>();\n\n  <span class="keyword control">await</span> <span class="class">Isolate</span>.<span class="method static">spawn</span>(\n    <span class="function">_startBackground</span>,\n    <span class="class constructor">_IsolateStartRequest</span>(<span class="variable">receivePort</span>.<span class="property instance">sendPort</span>, <span class="variable">path</span>),\n  );\n\n  <span class="comment">// _startBackground will send the DriftIsolate to this ReceivePort</span>\n  <span class="keyword control">return</span> <span class="keyword control">await</span> <span class="variable">receivePort</span>.<span class="property instance">first</span> <span class="keyword">as</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>;\n}\n\n<span class="keyword void">void</span> <span class="function declaration static">_startBackground</span>(<span class="class">_IsolateStartRequest</span> <span class="parameter declaration">request</span>) {\n  <span class="comment">// this is the entry point from the background isolate! Let\'s create</span>\n  <span class="comment">// the database from the path we received</span>\n  <span class="keyword">final</span> <span class="variable declaration">executor</span> = <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>(<span class="class constructor">File</span>(<span class="parameter">request</span>.<span class="property instance">targetPath</span>));\n  <span class="comment">// we\'re using DriftIsolate.inCurrent here as this method already runs on a</span>\n  <span class="comment">// background isolate. If we used DriftIsolate.spawn, a third isolate would be</span>\n  <span class="comment">// started which is not what we want!</span>\n  <span class="keyword">final</span> <span class="variable declaration">driftIsolate</span> = <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/DriftIsolate.inCurrent.html">inCurrent</a></span>(\n    () =&gt; <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span>(<span class="variable">executor</span>),\n  );\n  <span class="comment">// inform the starting isolate about this, so that it can call .connect()</span>\n  <span class="parameter">request</span>.<span class="property instance">sendDriftIsolate</span>.<span class="method instance">send</span>(<span class="variable">driftIsolate</span>);\n}\n\n<span class="comment">// used to bundle the SendPort and the target path, since isolate entry point</span>\n<span class="comment">// functions can only take one parameter.</span>\n<span class="keyword">class</span> <span class="class declaration">_IsolateStartRequest</span> {\n  <span class="keyword">final</span> <span class="class">SendPort</span> <span class="variable declaration instance">sendDriftIsolate</span>;\n  <span class="keyword">final</span> <span class="class">String</span> <span class="variable declaration instance">targetPath</span>;\n\n  <span class="class constructor declaration">_IsolateStartRequest</span>(<span class="keyword">this</span>.<span class="variable instance">sendDriftIsolate</span>, <span class="keyword">this</span>.<span class="variable instance">targetPath</span>);\n}\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span> <span class="function declaration static">createDriftIsolateAndConnect</span>() {\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection/DatabaseConnection.delayed.html">delayed</a></span>(\n    <span class="class constructor">Future</span>.<span class="method constructor">sync</span>(() <span class="keyword control">async</span> {\n      <span class="keyword">final</span> <span class="variable declaration">isolate</span> = <span class="keyword control">await</span> <span class="function">_createDriftIsolate</span>();\n      <span class="keyword control">return</span> <span class="keyword control">await</span> <span class="variable">isolate</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">connect</a></span>(<span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">singleClientMode</a></span>: <span class="boolean">true</span>);\n    }),\n  );\n}\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">createSimple</span>() {\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span>(() <span class="keyword control">async</span> {\n    <span class="keyword">final</span> <span class="variable declaration">dir</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n    <span class="keyword">final</span> <span class="variable declaration">file</span> = <span class="class constructor">File</span>(<span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dir</span>.<span class="property instance">path</span>, <span class="string">\'db.sqlite\'</span>));\n\n    <span class="comment">// Using createInBackground creates a drift isolate with the recommended</span>\n    <span class="comment">// options behind the scenes.</span>\n    <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="variable">file</span>);\n  });\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">invalidIsolateUsage</span>() <span class="keyword control">async</span> {\n  <span class="keyword">final</span> <span class="variable declaration">database</span> = <span class="class constructor">MyDatabase</span>(<span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/NativeDatabase.memory.html">memory</a></span>());\n\n  <span class="comment">// Unfortunately, this doesn\'t work: Drift databases contain references to</span>\n  <span class="comment">// async primitives like streams and futures that can\'t be serialized across</span>\n  <span class="comment">// isolates like this.</span>\n  <span class="keyword control">await</span> <span class="class">Isolate</span>.<span class="method static">run</span>(() <span class="keyword control">async</span> {\n    <span class="keyword control">await</span> <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/batch.html">batch</a></span>((<span class="parameter declaration">batch</span>) {\n      <span class="comment">// ...</span>\n    });\n  });\n}\n\n<span class="class">Future</span>&lt;<span class="class">List</span>&lt;<span class="class">SomeTableData</span>&gt;&gt; <span class="function declaration static">_complexAndExpensiveOperationToFetchRows</span>() <span class="keyword control">async</span> {\n  <span class="keyword control">throw</span> <span class="string">\'stub\'</span>;\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">insertBulkData</span>(<span class="class">MyDatabase</span> <span class="parameter declaration">database</span>) <span class="keyword control">async</span> {\n  <span class="comment">// computeWithDatabase is an extension provided by package:drift/isolate.dart</span>\n  <span class="keyword control">await</span> <span class="parameter">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase/computeWithDatabase.html">computeWithDatabase</a></span>(\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase/computeWithDatabase.html">computation</a></span>: (<span class="parameter declaration">database</span>) <span class="keyword control">async</span> {\n      <span class="comment">// Expensive computation that runs on its own isolate but talks to the</span>\n      <span class="comment">// main database.</span>\n      <span class="keyword">final</span> <span class="variable declaration">rows</span> = <span class="keyword control">await</span> <span class="function">_complexAndExpensiveOperationToFetchRows</span>();\n      <span class="keyword control">await</span> <span class="parameter">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/batch.html">batch</a></span>((<span class="parameter declaration">batch</span>) {\n        <span class="parameter">batch</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Batch/insertAll.html">insertAll</a></span>(<span class="parameter">database</span>.<span class="property instance">someTable</span>, <span class="variable">rows</span>);\n      });\n    },\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase/computeWithDatabase.html">connect</a></span>: (<span class="parameter declaration">connection</span>) {\n      <span class="comment">// This function is responsible for creating a second instance of your</span>\n      <span class="comment">// database class with a short-lived [connection].</span>\n      <span class="comment">// For this to work, your database class needs to have a constructor that</span>\n      <span class="comment">// allows taking a connection as described above.</span>\n      <span class="keyword control">return</span> <span class="class constructor">MyDatabase</span>(<span class="parameter">connection</span>);\n    },\n  );\n}\n\n<span class="class">Future</span>&lt;<span class="keyword void">void</span>&gt; <span class="function declaration static">customIsolateUsage</span>(<span class="class">MyDatabase</span> <span class="parameter declaration">database</span>) <span class="keyword control">async</span> {\n  <span class="keyword">final</span> <span class="variable declaration">connection</span> = <span class="keyword control">await</span> <span class="parameter">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/isolate/ComputeWithDriftIsolate/serializableConnection.html">serializableConnection</a></span>();\n\n  <span class="keyword control">await</span> <span class="class">Isolate</span>.<span class="method static">run</span>(() <span class="keyword control">async</span> {\n    <span class="comment">// We can\'t share the [database] object across isolates, but the connection</span>\n    <span class="comment">// is fine!</span>\n    <span class="keyword">final</span> <span class="variable declaration">databaseForIsolate</span> = <span class="class constructor">MyDatabase</span>(<span class="keyword control">await</span> <span class="variable">connection</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">connect</a></span>());\n\n    <span class="keyword control">try</span> {\n      <span class="keyword control">await</span> <span class="variable">databaseForIsolate</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/batch.html">batch</a></span>((<span class="parameter declaration">batch</span>) {\n        <span class="comment">// (...)</span>\n      });\n    } <span class="keyword control">finally</span> {\n      <span class="variable">databaseForIsolate</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase/close.html">close</a></span>();\n    }\n  }, <span class="parameter label">debugName</span>: <span class="string">\'My custom database task\'</span>);\n}\n</span>\n','isolate': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/isolate/isolate-library.html">\'package:drift/isolate.dart\'</a></span>;\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">tables</a></span>: [<span class="class">SomeTable</span>] <span class="comment">/* ... */</span><span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">MyDatabase</span> <span class="keyword">extends</span> <span class="class">_\$MyDatabase</span> {\n  <span class="comment">// A constructor like this can use the default connection as described in the</span>\n  <span class="comment">// getting started guide, but also allows overriding the connection.</span>\n  <span class="class constructor declaration">MyDatabase</span>([<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span>? <span class="parameter declaration">executor</span>]) : <span class="keyword">super</span>(<span class="parameter">executor</span> ?? <span class="function">_openConnection</span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n}\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() <span class="keyword control">async</span> {\n  <span class="keyword">final</span> <span class="variable declaration">isolate</span> = <span class="keyword control">await</span> <span class="function">createIsolate</span>();\n\n  <span class="comment">// After creating the isolate, calling connect() will return a connection</span>\n  <span class="comment">// which can be used to create a database.</span>\n  <span class="comment">// As long as the isolate is used by only one database (it is here), we can</span>\n  <span class="comment">// use `singleClientMode` to dispose the isolate after closing the connection.</span>\n  <span class="keyword">final</span> <span class="variable declaration">database</span> = <span class="class constructor">MyDatabase</span>(<span class="keyword control">await</span> <span class="variable">isolate</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">connect</a></span>(<span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate/connect.html">singleClientMode</a></span>: <span class="boolean">true</span>));\n\n  <span class="comment">// you can now use your database exactly like you regularly would, it</span>\n  <span class="comment">// transparently uses a background isolate to execute queries.</span>\n}</span>\n','initialization': '<span><span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n\n<span class="class">Future</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>&gt; <span class="function declaration static">_createDriftIsolate</span>() <span class="keyword control">async</span> {\n  <span class="comment">// this method is called from the main isolate. Since we can\'t use</span>\n  <span class="comment">// getApplicationDocumentsDirectory on a background isolate, we calculate</span>\n  <span class="comment">// the database path in the foreground isolate and then inform the</span>\n  <span class="comment">// background isolate about the path.</span>\n  <span class="keyword">final</span> <span class="variable declaration">dir</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n  <span class="keyword">final</span> <span class="variable declaration">path</span> = <span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dir</span>.<span class="property instance">path</span>, <span class="string">\'db.sqlite\'</span>);\n  <span class="keyword">final</span> <span class="variable declaration">receivePort</span> = <span class="class constructor">ReceivePort</span>();\n\n  <span class="keyword control">await</span> <span class="class">Isolate</span>.<span class="method static">spawn</span>(\n    <span class="function">_startBackground</span>,\n    <span class="class constructor">_IsolateStartRequest</span>(<span class="variable">receivePort</span>.<span class="property instance">sendPort</span>, <span class="variable">path</span>),\n  );\n\n  <span class="comment">// _startBackground will send the DriftIsolate to this ReceivePort</span>\n  <span class="keyword control">return</span> <span class="keyword control">await</span> <span class="variable">receivePort</span>.<span class="property instance">first</span> <span class="keyword">as</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/isolate/DriftIsolate-class.html">DriftIsolate</a></span>;\n}\n\n<span class="keyword void">void</span> <span class="function declaration static">_startBackground</span>(<span class="class">_IsolateStartRequest</span> <span class="parameter declaration">request</span>) {\n  <span class="comment">// this is the entry point from the background isolate! Let\'s create</span>\n  <span class="comment">// the database from the path we received</span>\n  <span class="keyword">final</span> <span class="variable declaration">executor</span> = <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>(<span class="class constructor">File</span>(<span class="parameter">request</span>.<span class="property instance">targetPath</span>));\n  <span class="comment">// we\'re using Drift