'lib/src/snippets/log_interceptor.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:async\'</span>;\n<span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string">\'dart_api/manager.dart\'</span>;\n\n<span class="keyword">class</span> <span class="class declaration">LogInterceptor</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryInterceptor-class.html">QueryInterceptor</a></span> {\n  <span class="class">Future</span>&lt;<span class="typeParameter">T</span>&gt; <span class="method declaration instance">_run</span>&lt;<span class="typeParameter">T</span>&gt;(\n    <span class="class">String</span> <span class="parameter declaration">description</span>,\n    <span class="class">FutureOr</span>&lt;<span class="typeParameter">T</span>&gt; <span class="keyword">Function</span>() <span class="parameter declaration">operation</span>,\n  ) <span class="keyword control">async</span> {\n    <span class="keyword">final</span> <span class="variable declaration">stopwatch</span> = <span class="class constructor">Stopwatch</span>()..<span class="method instance">start</span>();\n    <span class="function">print</span>(<span class="string">\'Running </span><span class="source interpolation">\$</span><span class="parameter">description</span><span class="string">\'</span>);\n\n    <span class="keyword control">try</span> {\n      <span class="keyword">final</span> <span class="variable declaration">result</span> = <span class="k