'lib/src/snippets/migrations/runtime_verification.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="comment">// import the migrations tooling</span>\n<span class="keyword">import</span> <span class="string">\'package:drift_dev/api/migrations_native.dart\'</span>;\n\n<span class="keyword">const</span> <span class="variable declaration">kDebugMode</span> = <span class="boolean">true</span>;\n\n<span class="keyword">abstract</span> <span class="keyword">class</span> <span class="class declaration">_\$MyDatabase</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase-class.html">GeneratedDatabase</a></span> {\n  <span class="class constructor declaration">_\$MyDatabase</span>(<span class="keyword">super</span>.<span class="parameter declaration">executor</span>);\n}\n\n\n<span class="keyword">class</span> <span class="class declaration">MyDatabase</span> <span class="keyword">extends</span> <span class="class">_\$MyDatabase</span> {\n  <span class="class constructor declaration">MyDatabase</span>(<span class="keyword">super</span>.<span class="parameter declaration">executor</span>);\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">Iterable</span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">TableInfo</a></span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span>, <span class="type">dynamic</span>&gt;&gt; <span class="keyword">get</span> <span class="property declaration instance">allTables</span> =&gt;\n      <span class="keyword control">throw</span> <span class="class constructor">UnimplementedError</span>();\n\n  <span class="an