'lib/src/snippets/migrations/tests/schema_test.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'package:test/test.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:drift_dev/api/migrations_native.dart\'</span>;\n\n<span class="comment">// The generated directory from before.</span>\n<span class="keyword">import</span> <span class="string">\'generated_migrations/schema.dart\'</span>;\n\n<span class="keyword">import</span> <span class="string">\'../migrations.dart\'</span>;\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() {\n  <span class="keyword">late</span> <span class="class">SchemaVerifier</span> <span class="variable declaration">verifier</span>;\n\n  <span class="function">setUpAll</span>(() {\n    <span class="comment">// GeneratedHelper() was generated by drift, the verifier is an api</span>\n    <span class="comment">// provided by drift_dev.</span>\n    <span class="variable">verifier</span> = <span class="class constructor">SchemaVerifier</span>(<span class="class constructor">GeneratedHelper</span>());\n  });\n\n  <span class="function">test</span>(<span class="string">\'upgrade from v1 to v2\'</span>, () <span class="keyword control">async</span> {\n    <span class="comment">// Use startAt(1) to obtain a database connection with all tables</span>\n    <span class="comment">// from the v1 schema.</span>\n    <span class="keyword">final</span> <span class="variable declaration">connection</span> = <span class="keyword control">await</span> <span class="variable">verifier</span>.<span class="method instance">startAt</span>(<span class="number">1</span>);\n    <span class="keyword">final</span> <span class="variable declaration">db</span> = <span class="class constructor">MyDatabase</span>(<span class="variable">connection</span>);\n\n    <span class="comment">// Use this to run a migration to v2 and then validate that the</span>\