'lib/src/snippets/modular/drift/example.drift.snippet.json': {'(full)': '<span><span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">todos</span> (\n    <span class="property">id</span> <span class="type">INT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> <span class="keyword">AUTOINCREMENT</span>,\n    <span class="property">title</span> <span class="type">TEXT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>,\n    <span class="property">content</span> <span class="type">TEXT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>,\n    <span class="property">category</span> <span class="type">INTEGER</span> <span class="keyword">REFERENCES</span> <span class="class">categories</span>(<span class="property">id</span>)\n);\n\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">categories</span> (\n    <span class="property">id</span> <span class="type">INT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> <span class="keyword">AUTOINCREMENT</span>,\n    <span class="property">description</span> <span class="type">TEXT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>\n) <span class="keyword">AS</span> Category;\n\n<span class="function declaration">filterTodos</span>: <span class="keyword">SELECT</span> * <span class="keyword">FROM</span> <span class="class">todos</span> <span class="keyword">WHERE</span> \$predicate;\n<span class="function declaration">getTodos</span> (\$predicate = <span class="keyword">TRUE</span>): <span class="keyword">SELECT</span> * <span class="keyword">FROM</span> <span class="class">todos</span> <span class="keyword">WHERE</span> \$predicate;</span>\n','filterTodos': '<span><span class="f