'lib/src/snippets/modular/drift/with_existing.drift.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'row_class.dart\'</span>; <span class="comment">--import for where the row class is defined</span>\n\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">users</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">name</span> <span class="type">TEXT</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span>\n) <span class="keyword">WITH</span> User; <span class="comment">-- This tells drift to use the existing Dart class</span>\n\n<span class="comment">-- table to demonstrate a more complex select query below.</span>\n<span class="comment">-- also, remember to add the import for `UserWithFriends` to your drift file.</span>\n<span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">friends</span> (\n  <span class="property">user_a</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">users</span>(<span class="property">id</span>),\n  <span class="property">user_b</span> <span class="type">INTEGER</span> <span class="keyword">NOT</span> <span class="keyword">NULL</span> <span class="keyword">REFERENCES</span> <span class="class">users</span>(<span class="property">id</span>),\n  <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span> (<span class="property">user_a</span>, <span class="property">user_b</span>)\n);\n\n<span class="function declaration">allFriendsOf</span> <span class="keyword">WITH</span> UserWithFriends: <span class="keyword">SELECT</span> users.** <span class="keyword">AS</span> user, <span 