'lib/src/snippets/platforms/encryption.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3/sqlite3.dart\'</span>;\n\n<span class="class">bool</span> <span class="function declaration static">_debugCheckHasCipher</span>(<span class="class">Database</span> <span class="parameter declaration">database</span>) {\n  <span class="keyword control">return</span> <span class="parameter">database</span>.<span class="method instance">select</span>(<span class="string">\'PRAGMA cipher;\'</span>).<span class="property instance">isNotEmpty</span>;\n}\n\n<span class="keyword void">void</span> <span class="function declaration static">databases</span>() {\n  <span class="keyword">final</span> <span class="variable declaration">myDatabaseFile</span> = <span class="class constructor">File</span>(<span class="string">\'/dev/null\'</span>);\n\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(\n    <span class="variable">myDatabaseFile</span>,\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">setup</a></span>: (<span class="parameter declaration">rawDb</span>) {\n      <span class="parameter">rawDb</span>.<span class="method instance">execute</span>(<span class="string">"PRAGMA key = \'passphrase\';"</span>);\n    },\n  );\n\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></sp