">get</span> <span class="property declaration instance">date</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/customType.html">customType</a></span>(<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes-class.html">PgTypes</a></span>.<span class="property static"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes/date-constant.html">date</a></span>)();\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Column-class.html">Column</a></span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDateTime-class.html">PgDateTime</a></span>&gt; <span class="keyword">get</span> <span class="property declaration instance">timestampWithTimezone</span> =&gt;\n      <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/customType.html">customType</a></span>(<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes-class.html">PgTypes</a></span>.<span class="property static"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes/timestampWithTimezone-constant.html">timestampWithTimezone</a></span>)();\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Column-class.html">Column</a></span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDateTime-class.html">PgDateTime</a></span>&gt; <span class="keyword">get</span> <span class="property declaration instance">timestampWithoutTimezone</span> =&gt;\n      <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/customType.html">customType</a></span>(<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes-class.html">PgTypes</a></span>.<span class="property static"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes/timestampNoTimezone-constant.html">timestampNoTimezone</a></span>)();\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Column-class.html">Column</a></span>&lt;<span class="class">Interval</span>&gt; <span class="keyword">get</span> <span class="property declaration instance">interval</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/customType.html">customType</a></span>(<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes-class.html">PgTypes</a></span>.<span class="property static"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes/interval-constant.html">interval</a></span>)();\n}</span>\n','time-dialectaware': '<span><span class="keyword">class</span> <span class="class declaration">_DialectAwareDateTimeType</span> <span class="keyword">implements</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/DialectAwareSqlType-class.html">DialectAwareSqlType</a></span>&lt;<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDateTime-class.html">PgDateTime</a></span>&gt; {\n  <span class="comment documentation">/// The underlying type used when this dialect-aware type is used on postgres</span>\n  <span class="comment documentation">/// databases.</span>\n  <span class="keyword">static</span> <span class="keyword">const</span> <span class="variable declaration static">_postgres</span> = <span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes-class.html">PgTypes</a></span>.<span class="property static"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgTypes/timestampWithTimezone-constant.html">timestampWithTimezone</a></span>;\n\n  <span class="co