'lib/src/snippets/platforms/postgres.dart.types.temp.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'package:uuid/uuid_value.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">i0</span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/drift_postgres-library.html">\'package:drift_postgres/drift_postgres.dart\'</a></span> <span class="keyword">as</span> <span class="variable importPrefix">i1</span>;\n<span class="keyword">import</span> <span class="string">\'package:postgres/src/types.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">i2</span>;\n<span class="keyword">typedef</span> <span class="type">T0</span> = <span class="variable importPrefix">i0</span>.<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/UuidValue-class.html">UuidValue</a></span>;\n<span class="keyword">typedef</span> <span class="type">T1</span> = <span class="variable importPrefix">i1</span>.<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDate-class.html">PgDate</a></span>;\n<span class="keyword">typedef</span> <span class="type">T2</span> = <span class="variable importPrefix">i1</span>.<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDate-class.html">PgDate</a></span>;\n<span class="keyword">typedef</span> <span class="type">T3</span> = <span class="variable importPrefix">i1</span>.<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDateTime-class.html">PgDateTime</a></span>;\n<span class="keyword">typedef</span> <span class="type">T4</span> = <span class="variable importPrefix">i1</span>.<span class="class"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDateTime-class.html">PgDateTim