'lib/src/snippets/platforms/stable_worker.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/wasm/wasm-library.html">\'package:drift/wasm.dart\'</a></span>;\n\n<span class="comment">// When compiled with dart2js, this file defines a dedicated or shared web</span>\n<span class="comment">// worker used by drift.</span>\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() =&gt; <span class="class"><a href="https://pub.dev/documentation/drift/latest/wasm/WasmDatabase-class.html">WasmDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/wasm/WasmDatabase/workerMainForOpen.html">workerMainForOpen</a></span>();</span>\n',},
'lib/src/snippets/platforms/vm.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">openDatabase</span>() {\n  <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="class constructor">File</span>(<span class="string">\'path/to/database.db\'</span>));\n}\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">openMultiThreadedDatabase</span>() {\n  <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(\n    <span class="class constructor">File</span>(<span class="string">\'path/to/database.db\'</span>),\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">setup</a></span>: (<span class="parameter declaration">database</span>) {\n      <span class="comment">// This is important, as accessing the database across threads otherwise</span>\n      <span class="comment">// causes "database locked" errors.</span>\n      <span class="comment">// With write-ahead logging (WAL) enabled, a single writer and multiple</span>\n      <span class="comment">// readers can operate on the database in parallel.</span>\n      <span class="parameter">database</span>.<span class="method instance">execute</span>(<span class="string">\'pragma journal_mode = WAL;\'</span>);\n    },\n    <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">readPool</a></span>: <span class="number">4</span>,\n  );\n}\n</span>\n','background-simple': '<span><span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">openDatabase</span>() {\n  <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="class constructor">File</span>(<span class="string">\'path/to/database.db\'</span>));\n}</span>\n','background-pool': '<span><span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="function declaration static">openMultiThreadedDatabase</span>() {\n  <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(\n    <span cl