'lib/src/snippets/platforms/workers.dart.snippet.json': {'(full)': '<span><span class="comment">// ignore_for_file: experimental_member_use</span>\n\n<span class="comment">// Note: This snippet describes a legacy API! Please consider migrating to</span>\n<span class="comment">// `package:drift/wasm.dart`, which has builtin support for web workers!</span>\n<span class="keyword">import</span> <span class="string">\'dart:html\'</span>; <span class="comment">// ignore: deprecated_member_use</span>\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/web/web-library.html">\'package:drift/web.dart\'</a></span>; <span class="comment">// ignore: deprecated_member_use</span>\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/web_worker/web_worker-library.html">\'package:drift/web/worker.dart\'</a></span>; <span class="comment">// ignore: deprecated_member_use</span>\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() {\n  <span class="comment">// Load sql.js library in the worker</span>\n  <span class="class">WorkerGlobalScope</span>.<span class="property static">instance</span>.<span class="method instance">importScripts</span>(<span class="string">\'sql-wasm.js\'</span>);\n\n  <span class="comment">// Call drift function that will set up this worker</span>\n  <span class="function"><a href="https://pub.dev/documentation/drift/latest/web_worker/web_worker-library.html">driftWorkerMain</a></span>(() {\n    <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/web/WebDatabase-class.html">WebDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/d