st/web_worker/DriftWorkerMode.html">DriftWorkerMode</a></span>.<span class="enumMember"><a href="https://pub.dev/documentation/drift/latest/web_worker">shared</a></span>,\n    ),\n  );\n}\n</span>\n','worker': '<span><span class="comment">// Note: This snippet describes a legacy API! Please consider migrating to</span>\n<span class="comment">// `package:drift/wasm.dart`, which has builtin support for web workers!</span>\n<span class="keyword">import</span> <span class="string">\'dart:html\'</span>; <span class="comment">// ignore: deprecated_member_use</span>\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/web/web-library.html">\'package:drift/web.dart\'</a></span>; <span class="comment">// ignore: deprecated_member_use</span>\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/web_worker/web_worker-library.html">\'package:drift/web/worker.dart\'</a></span>; <span class="comment">// ignore: deprecated_member_use</span>\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() {\n  <span class="comment">// Load sql.js library in the worker</span>\n  <span class="class">WorkerGlobalScope</span>.<span class="property static">instance</span>.<span class="method instance">importScripts</span>(<span class="string">\'sql-wasm.js\'</span>);\n\n  <span class="comment">// Call drift function that will set up this worker</span>\n  <span class="function"><a href="https://pub.dev/documentation/drift/latest/web_worker/web_worker-library.html">driftWorkerMain</a></span>(() {\n    <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/web/WebDatabase-class.html">WebDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/web/WebDatabase/WebDatabase.withStorage.html">withStorage</a></span>(\n      <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/web/DriftWebStorage-class.html">DriftWebStorage</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/web/DriftWebStorage/DriftWebStorage.indexedDb.html">indexedDb</a></span>(\n        <span class="string">\'worker\'</span>,\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/web/DriftWebStorage/DriftWebStorage.indexedDb.html">migrateFromLocalStorage</a></span>: <span class="boolean">false</span>,\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/web/DriftWebStorage/DriftWebStorage.indexedDb.html">inWebWorker</a></span>: <span class="boolean">true</span>,\n      ),\n    );\n  });\n}</span>\n','client': '<span><span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span> <span class="function declaration static">connectToWorker</span>() {\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection/DatabaseConnection.delayed.html">delayed</a></span>(\n    <span class="function"><a href="https://pub.dev/documentation/drift/latest/web_worker/web_worker-library.html">connectToDriftWorker</a></span>(\n      <span class="string">\'worker.dart.js\'</span>,\n      <span class="comment">// Note that SharedWorkers may not be available on all browsers and platforms.</span>\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/web_worker/web_worker-library.html">mode</a></span>: <span class="enum"><a href="https://pub.dev/documentation/drift/latest/web_worker/DriftWorkerMode.html">DriftWorkerMode</a></span>.<span class="enumMember"><a href="https://pub.dev/documentation/drift/latest/web_worker">shared</a></span>,\n    ),\n  );\n}\n</span>\n',},
'lib/src/snippets/setup/custom_flutter_setup.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3/sqlite3.dart\'</span>;\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span> <span class="function declaration static">openConnection</span>() {\n  <span class="comment">// the LazyDatabase util lets us find the right location for the file async.</span>\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span>(() <span class="keyword control">async</span> {\n    <span class="comment">// put the database file, called db.sqlite here, into the documents folder</span>\n    <span class="comment">// for your app.</span>\n    <span class="keyword">final</span> <span class="variable declaration">dbFolder</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n    <span class="keyword">final</span> <span class="variable declaration">file</span> = <span class="class constructor">File</span>(<span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dbFolder</span>.<span class="property instance">path</span>, <span class="string">\'db.sqlite\'</span>));\n\n    <span class="comment">// Make sqlite3 pick a more suitable location for temporary files - the</span>\n    <span class="comment">// one from the system may be inaccessible due to sandboxing.</span>\n    <span class="keyword">final</span> <span class="variable declaration">cachebase</span> = (<span class="keyword control">await</span> <span class="function">getTemporaryDirectory</span>()).<span class="property instance">path</span>;\n    <span class="comment">// We can\'t access /tmp on Android, which sqlite3 would try by default.</span>\n    <span class="comment">// Explicitly tell it about the correct temporary directory.</span>\n    <span class="property">sqlite3</span>.<span class="property instance">tempDirectory</span> = <span class="variable">cachebase</span>;\n\n    <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="variable">file</span>);\n  });\n}\n</span>\n','custom': '<span><span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:path/path.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">p</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3/sqlite3.dart\'</span>;\n\n<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span> <span class="function declaration static">openConnection</span>() {\n  <span class="comment">// the LazyDatabase util lets us find the right location for the file async.</span>\n  <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/LazyDatabase-class.html">LazyDatabase</a></span>(() <span class="keyword control">async</span> {\n    <span class="comment">// put the database file, called db.sqlite here, into the documents folder</span>\n    <span class="comment">// for your app.</span>\n    <span class="keyword">final</span> <span class="variable declaration">dbFolder</span> = <span class="keyword control">await</span> <span class="function">getApplicationDocumentsDirectory</span>();\n    <span class="keyword">final</span> <span class="variable declaration">file</span> = <span class="class constructor">File</span>(<span class="variable importPrefix">p</span>.<span class="function">join</span>(<span class="variable">dbFolder</span>.<span class="property instance">path</span>, <span class="string">\'db.sqlite\'</span>));\n\n    <span class="comment">// Make sqlite3 pick a more suitable location for temporary files - the</span>\n    <span class="comment">// one from the system may be inaccessible due to sandboxing.</span>\n    <span class="keyword">final</span> <span class="variable declaration">cachebase</span> = (<span class="keyword control">await</span> <span class="function">getTemporaryDirectory</span>()).<span class="property instance">path</span>;\n    <span class="comment">// We can\'t access /tmp on Android, which sqlite3 would try by default.</span>\n    <span class="comment">// Explicitly tell it about the correct temporary directory.</span>\n    <span class="property">sqlite3</span>.<span class="property instance">tempDirectory</span> = <span class="variable">cachebase</span>;\n\n    <span class="keyword control">return</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/createInBackground.html">createInBackground</a></span>(<span class="variable">file</span>);\n  });\n}\n</span>\n',},
'lib/src/snippets/setup/database.dart.snippet.json': {'(full)': '<span><span class="comment">// ignore_for_file: unused_element</span>\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">\'package:drift_flutter/drift_flutter.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:path_provider/path_provider.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'dart:io\'</span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/drift_postgres-library.html">\'package:drift_postgres/drift_postgres.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:postgres/postgres.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">pg</span>;\n\n\n<span class="keyword">part</span> <span class="string">\'database.g.dart\'</span>;\n\n<span class="keyword">class</span> <span class="class declaration">TodoItems</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Table-class.html">Table</a></span> {\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/IntColumn.html">IntColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">id</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/integer.html">integer</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildIntColumn/autoIncrement.html">autoIncrement</a></span>()();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">title</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildTextColumn/withLength.html">withLength</a></span>(<span class="parameter label">min</span>: <span class="number">6</span>, <span class="parameter label">max</span>: <span class="number">32</span>)();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/TextColumn.html">TextColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">content</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/text.html">text</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildGeneralColumn/named.html">named</a></span>(<span class="string">\'body\'</span>)();\n  <span class="type"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeColumn.html">DateTimeColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">createdAt</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/dateTime.html">dateTime</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildGeneralColumn/nullable.html">nullable</a></span>()();\n}\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">tables</a></span>: [<span class="class">TodoItems</span>]<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">AppDatabase</span> <span class="keyword">extends</span> <span class="class">_\$AppDatabase</span> {\n  <span class="comment">// After generating code, this class needs to define a `schemaVersion` getter</span>\n  <span class="comment">// and a constructor telling drift where the database should be stored.</span>\n  <span class="comment">// These are described in the getting started guide: https://drift.simonbinder.eu/setup/</span>\n  <span class="class constructor declaration">AppDatabase</span>([<span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span>? <span class="parameter declaration">executor</span>]) : <span class="keyword">super</span>(<span class="parameter">executor</span> ?? <span class="method static">_openConnection</span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="number">1</span>;\n\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="method declaration static">_openConnection</span>() {\n    <span class="keyword control">throw</span> <span class="string">\'should not show as snippet\'</span>;\n  }\n\n}\n\n<span class="keyword">class</span> <span class="class declaration">OpenFlutter</span> {\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="method declaration static">_openConnection</span>() {\n    <span class="keyword control">return</span> <span class="function"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">driftDatabase</a></span>(\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">name</a></span>: <span class="string">\'my_database\'</span>,\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/drift_flutter-library.html">native</a></span>: <span class="keyword">const</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/DriftNativeOptions-class.html">DriftNativeOptions</a></span>(\n        <span class="comment">// By default, `driftDatabase` from `package:drift_flutter` stores the</span>\n        <span class="comment">// database files in `getApplicationDocumentsDirectory()`.</span>\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift_flutter/latest/drift_flutter/DriftNativeOptions/DriftNativeOptions.html">databaseDirectory</a></span>: <span class="function">getApplicationSupportDirectory</span>,\n      ),\n      <span class="comment">// If you need web support, see https://drift.simonbinder.eu/platforms/web/</span>\n    );\n  }\n}\n\n<span class="keyword">class</span> <span class="class declaration">OpenPostgres</span> {\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="method declaration static">_openConnection</span>() {\n    <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift_postgres/latest/drift_postgres/PgDatabase-class.html">PgDatabase</a></span>(\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift_postgres/