cumentation/drift/latest/drift/DateTimeColumn.html">DateTimeColumn</a></span> <span class="keyword">get</span> <span class="property declaration instance">createdAt</span> =&gt; <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Table/dateTime.html">dateTime</a></span>().<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/BuildGeneralColumn/nullable.html">nullable</a></span>()();\n}\n</span>\n','use': '<span><span class="keyword void">void</span> <span class="function declaration static">main</span>() <span class="keyword control">async</span> {\n  <span class="class">WidgetsFlutterBinding</span>.<span class="method static">ensureInitialized</span>();\n\n  <span class="keyword">final</span> <span class="variable declaration">database</span> = <span class="class constructor">AppDatabase</span>();\n\n  <span class="keyword control">await</span> <span class="variable">database</span>\n      .<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/into.html">into</a></span>(<span class="variable">database</span>.<span class="property instance">todoItems</span>)\n      .<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/InsertStatement/insert.html">insert</a></span>(\n        <span class="class constructor">TodoItemsCompanion</span>.<span class="method constructor">insert</span>(\n          <span class="parameter label">title</span>: <span class="string">\'todo: finish drift setup\'</span>,\n          <span class="parameter label">content</span>: <span class="string">\'We can now write queries and define our own tables.\'</span>,\n        ),\n      );\n  <span class="class">List</span>&lt;<span class="class">TodoItem</span>&gt; <span class="variable declaration">allItems</span> = <span class="keyword control">await</span> <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/select.html">select</a></span>(<span class="variable">database</span>.<span class="property instance">todoItems</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/SimpleSelectStatement/get.html">get</a></span>();\n\n  <span class="function">print</span>(<span class="string">\'items in database: </span><span class="source interpolation">\$</span><span class="variable">allItems</span><span class="string">\'</span>);\n}\n</span>\n',},
'lib/src/snippets/setup/migrate_to_drift/database.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n\n<span class="keyword">part</span> <span class="string">\'database.g.dart\'</span>;\n\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase-class.html">DriftDatabase</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftDatabase/DriftDatabase.html">include</a></span>: {<span class="string">\'schema.drift\'</span>}<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">AppDatabase</span> <span class="keyword">extends</span> <span class="class">_\$AppDatabase</span> {\n  <span class="class constructor declaration">AppDatabase</span>() : <span class="keyword">super</span>(<span class="method static">_openDatabase</span>());\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">int</span> <span class="keyword">get</span> <span class="property declaration instance">schemaVersion</span> =&gt; <span class="keyword control">throw</span> <span class="class constructor">UnimplementedError</span>(\n    <span class="string">\'todo: The schema version used by your existing database\'</span>,\n  );\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy-class.html">MigrationStrategy</a></span> <span class="keyword">get</span> <span class="property declaration instance">migration</span> {\n    <span class="keyword control">return</span> <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy-class.html">MigrationStrategy</a></span>(\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy/MigrationStrategy.html">onCreate</a></span>: (<span class="parameter declaration">m</span>) <span class="keyword control">async</span> {\n        <span class="keyword control">await</span> <span class="parameter">m</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Migrator/createAll.html">createAll</a></span>();\n      },\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy/MigrationStrategy.html">onUpgrade</a></span>: (<span class="parameter declaration">m</span>, <span class="parameter declaration">from</span>, <span class="parameter declaration">to</span>) <span class="keyword control">async</span> {\n        <span class="comment">// This is similar to the `onUpgrade` callback from sqflite. When</span>\n        <span class="comment">// migrating to drift, it should contain your existing migration logic.</span>\n        <span class="comment">// You can access the raw database by using `customStatement`</span>\n      },\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy/MigrationStrategy.html">beforeOpen</a></span>: (<span class="parameter declaration">details</span>) <span class="keyword control">async</span> {\n        <span class="comment">// This is a good place to enable pragmas you expect, e.g.</span>\n        <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customStatement.html">customStatement</a></span>(<span class="string">\'pragma foreign_keys = ON;\'</span>);\n      },\n    );\n  }\n\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="method declaration static">_openDatabase</span>() {\n    <span class="keyword control">throw</span> <span class="class constructor">UnimplementedError</span>(\n      <span class="string">\'todo: Open database compatible with the one that already exists\'</span>,\n    );\n  }\n\n  <span class="class">Future</span>&lt;<span class="class">List</span>&lt;<span class="class">TestData</span>&gt;&gt; <span class="method declaration instance">queryWithGeneratedCode</span>() <span class="keyword control">async</span> {\n    <span class="keyword control">return</span> <span class="method instance">findWithValue</span>(<span class="number">12</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/get.html">get</a></span>();\n  }\n\n  <span class="class">Stream</span>&lt;<span class="class">List</span>&lt;<span class="class">TestData</span>&gt;&gt; <span class="method declaration instance">queryWithDartCode</span>() {\n    <span class="keyword">final</span> <span class="variable declaration">query</span> = <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/select.html">select</a></span>(<span class="property instance">test</span>)..<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/where.html">where</a></span>((<span class="parameter declaration">row</span>) =&gt; <span class="parameter">row</span>.<span class="property instance">value</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ComparableExpr/isBiggerThanValue.html">isBiggerThanValue</a></span>(<span class="number">12</span>));\n    <span class="keyword control">return</span> <span class="variable">query</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/SimpleSelectStatement/watch.html">watch</a></span>();\n  }\n\n}\n</span>\n','start': '<span>