abel"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy/MigrationStrategy.html">onCreate</a></span>: (<span class="parameter declaration">m</span>) <span class="keyword control">async</span> {\n        <span class="keyword control">await</span> <span class="parameter">m</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Migrator/createAll.html">createAll</a></span>();\n      },\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy/MigrationStrategy.html">onUpgrade</a></span>: (<span class="parameter declaration">m</span>, <span class="parameter declaration">from</span>, <span class="parameter declaration">to</span>) <span class="keyword control">async</span> {\n        <span class="comment">// This is similar to the `onUpgrade` callback from sqflite. When</span>\n        <span class="comment">// migrating to drift, it should contain your existing migration logic.</span>\n        <span class="comment">// You can access the raw database by using `customStatement`</span>\n      },\n      <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/MigrationStrategy/MigrationStrategy.html">beforeOpen</a></span>: (<span class="parameter declaration">details</span>) <span class="keyword control">async</span> {\n        <span class="comment">// This is a good place to enable pragmas you expect, e.g.</span>\n        <span class="keyword control">await</span> <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/customStatement.html">customStatement</a></span>(<span class="string">\'pragma foreign_keys = ON;\'</span>);\n      },\n    );\n  }\n\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/QueryExecutor-class.html">QueryExecutor</a></span> <span class="method declaration static">_openDatabase</span>() {\n    <span class="keyword control">throw</span> <span class="class constructor">UnimplementedError</span>(\n      <span class="string">\'todo: Open database compatible with the one that already exists\'</span>,\n    );\n  }\n\n}\n</span>\n','drift-query': '<span><span class="class">Future</span>&lt;<span class="class">List</span>&lt;<span class="class">TestData</span>&gt;&gt; <span class="method declaration instance">queryWithGeneratedCode</span>() <span class="keyword control">async</span> {\n  <span class="keyword control">return</span> <span class="method instance">findWithValue</span>(<span class="number">12</span>).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/get.html">get</a></span>();\n}</span>\n','dart-query': '<span><span class="class">Stream</span>&lt;<span class="class">List</span>&lt;<span class="class">TestData</span>&gt;&gt; <span class="method declaration instance">queryWithDartCode</span>() {\n  <span class="keyword">final</span> <span class="variable declaration">query</span> = <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/select.html">select</a></span>(<span class="property instance">test</span>)..<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/where.html">where</a></span>((<span class="parameter declaration">row</span>) =&gt; <span class="parameter">row</span>.<span class="property instance">value</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/ComparableExpr/isBiggerThanValue.html">isBiggerThanValue</a></span>(<span class="number">12</span>));\n  <span class="keyword control">return</span> <span class="variable">query</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/SimpleSelectStatement/watch.html">watch</a></span>();\n}\n</span>\n',},
'lib/src/snippets/setup/migrate_to_drift/schema.drift.snippet.json': {'(full)': '<span><span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">Test</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">name</span> <span class="type">TEXT</span>,\n  <span class="property">value</span> <span class="type">INTEGER</span>,\n  <span class="property">num</span> <span class="type">REAL</span>\n);\n\n<span class="function declaration">findWithValue</span>: <span class="keyword">SELECT</span> * <span class="keyword">FROM</span> <span class="class">Test</span> <span class="keyword">WHERE</span> <span class="property">value</span> &gt; <span class="variable">?</span>;</span>\n','test': '<span><span class="keyword">CREATE</span> <span class="keyword">TABLE</span> <span class="class declaration">Test</span> (\n  <span class="property">id</span> <span class="type">INTEGER</span> <span class="keyword">PRIMARY</span> <span class="keyword">KEY</span>,\n  <span class="property">name</span> <span class="type">TEXT</span>,\n  <span class="property">value</span> <span class="type">INTEGER</span>,\n  <span class="property">num</span> <span class="type">REAL</span>\n);</span>\n','query': '<span><span class="function declaration">findWithValue</span>: <span class="keyword">SELECT</span> * <span class="keyword">FROM</span> <span class="class">Test</span> <span class="keyword">WHERE</span> <span class="property">value</span> &gt; <span class="variable">?</span>;</span>\n',},
'lib/src/snippets/setup/migrate_to_drift/schema.expr.temp.dart.snippet.json': {'(full)': '<span></span>\n',},
'lib/src/snippets/setup/testing.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:test/test.dart\'</span>;\n<span class="comment">// the file defined above, you can test any drift database of course</span>\n<span class="keyword">import</span> <span class="string">\'database.dart\'</span>;\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() {\n  <span class="keyword">late</span> <span class="class">AppDatabase</span> <span class="variable declaration">database</span>;\n\n  <span class="function">setUp</span>(() {\n    <span class="variable">database</span> = <span class="class constructor">AppDatabase</span>(\n      <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span>(\n        <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/NativeDatabase.memory.html">memory</a></span>(),\n        <span class="comment">// Recommended for widget tests to avoid test errors.</span>\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection/DatabaseConnection.html">closeStreamsSynchronously</a></span>: <span class="boolean">true</span>,\n      ),\n    );\n  });\n  <span class="function">tearDown</span>(() <span class="keyword control">async</span> {\n    <span class="keyword control">await</span> <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase/close.html">close</a></span>();\n  });\n}</span>\n',},
'lib/src/snippets/setup/testing_deterministic.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'package:clock/clock.dart\'</span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:file/local.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3/sqlite3.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3_test/sqlite3_test.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:uuid/uuid.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:test/test.dart\'</span>;\n\n<span class="keyword">import</span> <span class="string">\'../platforms/postgres.dart\'</span>;\n\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() {\n  <span class="keyword">late</span> <span class="class">TestSqliteFileSystem</span> <span class="variable declaration">vfs</span>;\n\n  <span class="function">setUpAll</span>(() {\n    <span class="variable">vfs</span> = <span class="class constructor">TestSqliteFileSystem</span>(<span class="parameter label">fs</span>: <span class="keyword">const</span> <span class="class constructor">LocalFileSystem</span>(), <span class="parameter label">name</span>: <span class="class constructor">Uuid</span>().<span class="method instance">v4</span>());\n    <span class="property">sqlite3</span>.<span class="method instance">registerVirtualFileSystem</span>(<span class="variable">vfs</span>);\n  });\n  <span class="function">tearDownAll</span>(() =&gt; <span class="property">sqlite3</span>.<span class="method instance">unregisterVirtualFileSystem</span>(<span class="variable">vfs</span>));\n\n  <span class="keyword">late</span> <span class="class">MyDatabase</span> <span class="variable declaration">database</span>;\n\n  <span class="function">setUp</span>(() {\n    <span class="keyword">final</span> <span class="variable declaration">rawDatabase</span> = <span class="property">sqlite3</span>.<span class="method instance">openInMemory</span>(<span class="parameter label">vfs</span>: <span class="variable">vfs</span>.<span class="property instance">name</span>);\n\n    <span class="variable">database</span> = <span class="class constructor">MyDatabase</span>(\n      <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection-class.html">DatabaseConnection</a></span>(\n        <span class="class constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase-class.html">NativeDatabase</a></span>.<span class="method constructor"><a href="https://pub.dev/documentation/drift/latest/native/NativeDatabase/NativeDatabase.opened.html">opened</a></span>(<span class="variable">rawDatabase</span>),\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnection/DatabaseConnection.html">closeStreamsSynchronously</a></span>: <span class="boolean">true</span>,\n      ),\n    );\n  });\n  <span class="function">tearDown</span>(() <span class="keyword control">async</span> {\n    <span class="keyword control">await</span> <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/GeneratedDatabase/close.html">close</a></span>();\n  });\n\n  <span class="function">test</span>(<span class="string">\'my test depending on database time\'</span>, () <span class="keyword control">async</span> {\n    <span class="comment">// The VFS uses package:clock to get the current time, which can be</span>\n    <span class="comment">// overridden for tests:</span>\n    <span class="keyword">final</span> <span class="variable declaration">moonLanding</span> = <span class="class constructor">DateTime</span>.<span class="method constructor">utc</span>(<span class="number">1969</span>, <span class="number">7</span>, <span class="number">20</span>, <span class="number">20</span>, <span class="number">18</span>, <span class="number">04</span>);\n    <span class="keyword control">await</span> <span class="function">withClock</span>(<span class="class constructor">Clock</span>.<span class="method constructor">fixed</span>(<span class="variable">moonLanding</span>), () <span class="keyword control">async</span> {\n      <span class="comment">// This reads the time directly, but indirect references (e.g. in triggers</span>\n      <span class="comment">// or default columns) would also use the mocked time.</span>\n      <span class="keyword">final</span> <span class="variable declaration">row</span> = <span class="keyword control">await</span> <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/selectExpressions.html">selectExpressions</a></span>([\n        <span class="property">currentDateAndTime</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeExpressions/year.html">year</a></span>,\n      ]).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/getSingle.html">getSingle</a></span>();\n\n      <span class="function">expect</span>(<span class="variable">row</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedResult/read.html">read</a></span>(<span class="property">currentDateAndTime</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeExpressions/year.html">year</a></span>)!, <span class="number">1969</span>);\n    });\n  });\n}\n</span>\n','setup': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/native/native-library.html">\'package:drift/native.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:file/local.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3/sqlite3.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:sqlite3_test/sqlite3_test.dart\'</span>;\n<span class="keyword">import</span> <span class="string">\'package:uuid/uuid.dart\'</span>;\n\n<span class="keyword void">void</span> <span class="function declaration static">main</span>() {\n  <span class="keyword">late</span> <span class="class">TestSqliteFileSystem</span> <span class="variable declaration">vfs</span>;\n\n  <span class="function">setUpAll</span>(() {\n    <span class="variable">vfs</span> = <span class="class constructor">TestSqliteFileSystem</span>(<span class="parameter label">fs</span>: <span class="keyword">const</span> <span class="class constructor">LocalFileSystem</span>(), <span class="parameter label">name</span>: <span class="class constructor">Uuid</span>().<span class="method instance">v4</span>());\n    <span class="property">sqlite3</span>.<span class="method instance">registerVirtualFileSystem</span>(<span class="variable">vfs</span>);\n  });\n  <span class="function">tearDownAll</span>(() =&gt; <span class="property">sqlite3</span>.<span class="method instance">unregisterVirtualFileSystem</span>(<span class="variable">vfs</span>));\n}\n</span>\n','test': '<span><span class="function">test</span>(<span class="string">\'my test depending on database time\'</span>, () <span class="keyword control">async</span> {\n  <span class="comment">// The VFS uses package:clock to get the current time, which can be</span>\n  <span class="comment">// overridden for tests:</span>\n  <span class="keyword">final</span> <span class="variable declaration">moonLanding</span> = <span class="class constructor">DateTime</span>.<span class="method constructor">utc</span>(<span class="number">1969</span>, <span class="number">7</span>, <span class="number">20</span>, <span class="number">20</span>, <span class="number">18</span>, <span class="number">04</span>);\n  <span class="keyword control">await</span> <span class="function">withClock</span>(<span class="class constructor">Clock</span>.<span class="method constructor">fixed</span>(<span class="variable">moonLanding</span>), () <span class="keyword control">async</span> {\n    <span class="comment">// This reads the time directly, but indirect references (e.g. in triggers</span>\n    <span class="comment">// or default columns) would also use the mocked time.</span>\n    <span class="keyword">final</span> <span class="variable declaration">row</span> = <span class="keyword control">await</span> <span class="variable">database</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/selectExpressions.html">selectExpressions</a></span>([\n      <span class="property">currentDateAndTime</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeExpressions/year.html">year</a></span>,\n    ]).<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/Selectable/getSingle.html">getSingle</a></span>();\n\n    <span class="function">expect</span>(<span class="variable">row</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/TypedResult/read.html">read</a></span>(<span class="property">currentDateAndTime</span>.<span class="property instance"><a href="https://pub.dev/documentation/drift/latest/drift/DateTimeExpressions/year.html">year</a></span>)!, <span class="number">1969</span>);\n  });\n});</span>\n',},
'lib/src/snippets/setup/todos_dao.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'database.dart\'</span>;\n\n<span class="keyword">part</span> <span class="string">\'todos_dao.g.dart\'</span>;\n\n<span class="comment">// the _TodosDaoMixin will be created by drift. It contains all the necessary</span>\n<span class="comment">// fields for the tables. The &lt;MyDatabase&gt; type annotation is the database class</span>\n<span class="comment">// that should use this dao.</span>\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftAccessor-class.html">DriftAccessor</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftAccessor/DriftAccessor.html">tables</a></span>: [<span class="class">TodoItems</span>]<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">TodosDao</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseAccessor-class.html">DatabaseAccessor</a></span>&lt;<span class="class">AppDatabase</span>&gt; <span class="keyword">with</span> <span class="class">_\$TodosDaoMixin</span> {\n  <span class="comment">// this constructor is required so that the main database can create an instance</span>\n  <span class="comment">// of this object.</span>\n  <span class="class constructor declaration">TodosDao</span>(<span class="keyword">super</span>.<span class="parameter declaration">attachedDatabase</span>);\n\n  <span class="class">Stream</span>&lt;<span class="class">List</span>&lt;<span class="class">TodoItem</span>&gt;&gt; <span class="method declaration instance">findTodos</span>(<span class="class">String</span>? <span class="parameter declaration">contentFilter</span>) {\n    <span class="keyword">final</span> <span class="variable declaration">query</span> = <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/select.html">select</a></span>(<span class="property instance">todoItems</span>);\n    <span class="keyword control">if</span> (<span class="parameter">contentFilter</span> <span class="keyword control">case</span> <span class="keyword">final</span> <span class="variable declaration">filter</span>?) {\n      <span class="variable">query</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/where.html">where</a></span>((<span class="parameter declaration">item</span>) =&gt; <span class="parameter">item</span>.<span class="property instance">content</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/StringExpressionOperators/contains.html">contains</a></span>(<span class="variable">filter</span>));\n    }\n\n    <span class="keyword control">return</span> <span class="variable">query</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/SimpleSelectStatement/watch.html">watch</a></span>();\n  }\n}\n</span>\n','snippet': '<span><span class="keyword">part</span> <span class="string">\'todos_dao.g.dart\'</span>;\n\n<span class="comment">// the _TodosDaoMixin will be created by drift. It contains all the necessary</span>\n<span class="comment">// fields for the tables. The &lt;MyDatabase&gt; type annotation is the database class</span>\n<span class="comment">// that should use this dao.</span>\n<span class="annotation">@</span><span class="class annotation"><a href="https://pub.dev/documentation/drift/latest/drift/DriftAccessor-class.html">DriftAccessor</a></span><span class="annotation">(</span><span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/DriftAccessor/DriftAccessor.html">tables</a></span>: [<span class="class">TodoItems</span>]<span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">TodosDao</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseAccessor-class.html">DatabaseAccessor</a></span>&lt;<span class="class">AppDatabase</span>&gt; <span class="keyword">with</span> <span class="class">_\$TodosDaoMixin</span> {\n  <span class="comment">// this constructor is required so that the main database can create an instance</span>\n  <span class="comment">// of this object.</span>\n  <span class="class constructor declaration">TodosDao</span>(<span class="keyword">super</span>.<span class="parameter declaration">attachedDatabase</span>);\n\n  <span class="class">Stream</span>&lt;<span class="class">List</span>&lt;<span class="class">TodoItem</span>&gt;&gt; <span class="method declaration instance">findTodos</span>(<span class="class">String</span>? <span class="parameter declaration">contentFilter</span>) {\n    <span class="keyword">final</span> <span class="variable declaration">query</span> = <span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/DatabaseConnectionUser/select.html">select</a></span>(<span class="property instance">todoItems</span>);\n    <span class="keyword control">if</span> (<span class="parameter">contentFilter</span> <span class="keyword control">case</span> <span class="keyword">final</span> <span class="variable declaration">filter</span>?) {\n      <span class="variable">query</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/where.html">where</a></span>((<span class="parameter declaration">item</span>) =&gt; <span class="parameter">item</span>.<span class="property instance">content</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/StringExpressionOperators/contains.html">contains</a></span>(<span class="variable">filter</span>));\n    }\n\n    <span class="keyword control">return</span> <span class="variable">query</span>.<span class="method instance"><a href="https://pub.dev/documentation/drift/latest/drift/SimpleSelectStatement/watch.html">watch</a></span>();\n  }\n}\n</span>\n',},
'lib/src/snippets/type_converters/converters.dart.snippet.json': {'(full)': '<span><span class="keyword">import</span> <span class="string">\'dart:convert\'</span>;\n\n<span class="keyword">import</span> <span class="string"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">\'package:drift/drift.dart\'</a></span>;\n<span class="keyword">import</span> <span class="string">\'package:json_annotation/json_annotation.dart\'</span> <span class="keyword">as</span> <span class="variable importPrefix">j</span>;\n\n<span class="keyword">part</span> <span class="string">\'converters.g.dart\'</span>;\n\n<span class="annotation">@</span><span class="variable importPrefix">j</span><span class="annotation">.</span><span class="class annotation">JsonSerializable</span><span class="annotation">(</span><span class="annotation">)</span>\n<span class="keyword">class</span> <span class="class declaration">Preferences</span> {\n  <span class="class">bool</span> <span class="variable declaration instance">receiveEmails</span>;\n  <span class="class">String</span> <span class="variable declaration instance">selectedTheme</span>;\n\n  <span class="class constructor declaration">Preferences</span>(<span class="keyword">this</span>.<span class="variable instance">receiveEmails</span>, <span class="keyword">this</span>.<span class="variable instance">selectedTheme</span>);\n\n  <span class="keyword">factory</span> <span class="class constructor declaration">Preferences</span>.<span class="method constructor declaration">fromJson</span>(<span class="class">Map</span>&lt;<span class="class">String</span>, <span class="type">dynamic</span>&gt; <span class="parameter declaration">json</span>) =&gt;\n      <span class="function">_\$PreferencesFromJson</span>(<span class="parameter">json</span>);\n\n  <span class="class">Map</span>&lt;<span class="class">String</span>, <span class="type">dynamic</span>&gt; <span class="method declaration instance">toJson</span>() =&gt; <span class="function">_\$PreferencesToJson</span>(<span class="keyword">this</span>);\n\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">JsonTypeConverter2</a></span>&lt;<span class="class">Preferences</span>, <span class="class">String</span>, <span class="class">Object</span>?&gt; <span class="variable declaration static">converter</span> =\n      <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter-class.html">TypeConverter</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter/json2.html">json2</a></span>(\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter/json2.html">fromJson</a></span>: (<span class="parameter declaration">json</span>) =&gt; <span class="class constructor">Preferences</span>.<span class="method constructor">fromJson</span>(<span class="parameter">json</span> <span class="keyword">as</span> <span class="class">Map</span>&lt;<span class="class">String</span>, <span class="class">Object</span>?&gt;),\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter/json2.html">toJson</a></span>: (<span class="parameter declaration">pref</span>) =&gt; <span class="parameter">pref</span>.<span class="method instance">toJson</span>(),\n      );\n  <span class="keyword">static</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">JsonTypeConverter2</a></span>&lt;<span class="class">Preferences</span>, <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/Uint8List-class.html">Uint8List</a></span>, <span class="class">Object</span>?&gt; <span class="variable declaration static">binaryConverter</span> =\n      <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter-class.html">TypeConverter</a></span>.<span class="method static"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter/jsonb.html">jsonb</a></span>(\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter/jsonb.html">fromJson</a></span>: (<span class="parameter declaration">json</span>) =&gt; <span class="class constructor">Preferences</span>.<span class="method constructor">fromJson</span>(<span class="parameter">json</span> <span class="keyword">as</span> <span class="class">Map</span>&lt;<span class="class">String</span>, <span class="class">Object</span>?&gt;),\n        <span class="parameter label"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter/jsonb.html">toJson</a></span>: (<span class="parameter declaration">pref</span>) =&gt; <span class="parameter">pref</span>.<span class="method instance">toJson</span>(),\n      );\n}\n\n<span class="comment">// stores preferences as strings</span>\n<span class="keyword">class</span> <span class="class declaration">PreferenceConverter</span> <span class="keyword">extends</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/TypeConverter-class.html">TypeConverter</a></span>&lt;<span class="class">Preferences</span>, <span class="class">String</span>&gt;\n    <span class="keyword">with</span> <span class="class"><a href="https://pub.dev/documentation/drift/latest/drift/drift-library.html">JsonTypeConverter2</a></span>&lt;<span class="class">Preferences</span>, <span class="class">String</span>, <span class="class">Map</span>&lt;<span class="class">String</span>, <span class="class">Object</span>?&gt;&gt; {\n  <span class="keyword">const</span> <span class="class constructor declaration">PreferenceConverter</span>();\n\n  <span class="annotation">@</span><span class="property annotation">override</span>\n  <span class="class">Preferences</span> <span class="method declaration instance">fromSql